import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { User, Notification as NotificationType, AuthUser } from './types';
import { AppContextProvider } from './context/AppContext';
import MainLayout from './components/layout/MainLayout';
import LandingPage from './components/layout/LandingPage';
import LoginModal from './components/auth/LoginModal';
import Notification from './components/ui/Notification';
import LegacyAppContainer from './components/modules/LegacyAppContainer';
import WorkManager from './components/modules/WorkManager';
import PayrollManager from './components/modules/PayrollManager';
import PublicFeedbackPortal from './components/portal/PublicFeedbackPortal';
import { kpiMonitorHtml } from './components/modules/moduleContent';
import * as db from './services/db';
import { 
    INITIAL_USER_DATA, 
    INITIAL_CLIENTS_DATA, 
    INITIAL_CONTACTS_DATA, 
    INITIAL_CENTRES_DATA, 
    INITIAL_FRAMING_DATA, 
    INITIAL_FINISH_DATA,
    APP_VERSION
} from './constants';

type Module = 'dashboard' | 'project-board' | 'kpi-monitor' | 'payroll-manager' | 'work-manager' | 'feedback-portal';

const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [activeModule, setActiveModule] = useState<Module>('dashboard');
    const [notification, setNotification] = useState<NotificationType | null>(null);
    const [isInitialized, setIsInitialized] = useState(false);
    const [portalToken, setPortalToken] = useState<string | null>(null);

    // Resilient Background Sync Logic
    useEffect(() => {
        const triggerSync = () => {
            const meta = db.getSystemMeta();
            if (navigator.onLine && meta.driveAccessToken) {
                console.log("Sync Triggered: Refreshing cloud data...");
                db.syncWithCloud().catch(() => {});
            }
        };

        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                triggerSync();
            }
        };

        window.addEventListener('online', triggerSync);
        document.addEventListener('visibilitychange', handleVisibilityChange);

        // Periodic background check (every 2 mins for collaboration)
        const interval = setInterval(triggerSync, 120000);

        return () => {
            window.removeEventListener('online', triggerSync);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
            clearInterval(interval);
        };
    }, []);

    // Initialize Database
    useEffect(() => {
        const initDB = async () => {
            const meta = db.getSystemMeta();
            const existingUsers = db.getData<AuthUser>('users');

            // Check for Portal Token in URL
            const urlParams = new URLSearchParams(window.location.search);
            const token = urlParams.get('p_feedback');
            if (token) {
                setPortalToken(token);
                setActiveModule('feedback-portal');
            }

            // 1. Local Fallback Provisioning
            if (existingUsers.length === 0 && !meta.driveAccessToken) {
                db.saveData('users', INITIAL_USER_DATA as any);
                db.saveData('clients', INITIAL_CLIENTS_DATA as any);
                db.saveData('contacts', INITIAL_CONTACTS_DATA as any);
                db.saveData('centres', INITIAL_CENTRES_DATA as any);
                db.saveData('framingMaterials', INITIAL_FRAMING_DATA as any);
                db.saveData('finishMaterials', INITIAL_FINISH_DATA as any);
            }

            // 2. Silent Cloud Pull on Boot
            if (navigator.onLine && meta.driveAccessToken) {
                try {
                    await db.syncWithCloud();
                } catch (e) {
                    console.warn("Background sync deferred.");
                }
            }

            setIsInitialized(true);
        };
        initDB();
    }, []);

    const showNotification = useCallback((message: string, type: 'success' | 'error' | 'warning' = 'success') => {
        setNotification({ message, type });
        setTimeout(() => setNotification(null), 4000);
    }, []);

    const contextValue = useMemo(() => ({
        currentUser,
        setCurrentUser,
        showNotification
    }), [currentUser, showNotification]);

    const handleLogin = (user: User) => {
        setCurrentUser(user);
        setActiveModule('dashboard');
    };

    const renderContent = () => {
        if (activeModule === 'feedback-portal' && portalToken) {
            return <PublicFeedbackPortal token={portalToken} />;
        }

        switch (activeModule) {
            case 'project-board':
                return <MainLayout onBack={() => setActiveModule('dashboard')} />;
            case 'kpi-monitor':
                return <LegacyAppContainer htmlContent={kpiMonitorHtml} title="KPI Monitor" onBack={() => setActiveModule('dashboard')} />;
            case 'payroll-manager':
                return <PayrollManager onBack={() => setActiveModule('dashboard')} onNavigate={setActiveModule} />;
            case 'work-manager':
                return <WorkManager onBack={() => setActiveModule('dashboard')} />;
            case 'dashboard':
            default:
                return <LandingPage onNavigate={setActiveModule} onLogout={() => setCurrentUser(null)} />;
        }
    };

    if (!isInitialized) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-slate-950 text-white">
                <div className="flex flex-col items-center gap-6">
                    <div className="relative">
                        <div className="absolute inset-0 bg-blue-500 blur-2xl opacity-20 animate-pulse"></div>
                        <i className="fas fa-circle-notch animate-spin text-5xl text-blue-500 relative z-10"></i>
                    </div>
                    <div className="text-center animate-pulse">
                        <p className="font-black tracking-[0.4em] text-[10px] uppercase mb-1">Authenticating</p>
                        <p className="text-[8px] text-slate-600 font-bold uppercase">Connecting Repository</p>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <AppContextProvider value={contextValue}>
            {(currentUser || activeModule === 'feedback-portal') ? renderContent() : <LoginModal onLogin={handleLogin} />}
            {notification && <Notification message={notification.message} type={notification.type} />}
        </AppContextProvider>
    );
};

export default App;

import React, { useState, useEffect } from 'react';
import Icon from '../ui/Icon';
import Button from '../ui/Button';
import { CustomerFeedback } from '../../types';

interface PublicFeedbackPortalProps {
    token: string;
}

const PublicFeedbackPortal: React.FC<PublicFeedbackPortalProps> = ({ token }) => {
    const [projectData, setProjectData] = useState<{ name: string; code: string; value: number } | null>(null);
    const [rating, setRating] = useState(0);
    const [quality, setQuality] = useState(0);
    const [timeliness, setTimeliness] = useState(0);
    const [communication, setCommunication] = useState(0);
    const [comments, setComments] = useState('');
    const [isSubmitted, setIsSubmitted] = useState(false);
    const [signedCode, setSignedCode] = useState('');

    useEffect(() => {
        try {
            // Token is Base64 encoded: "PROJECT_CODE|PROJECT_NAME|VALUE"
            const decoded = atob(token);
            const [code, name, value] = decoded.split('|');
            setProjectData({ code, name, value: parseFloat(value) || 0 });
        } catch (e) {
            console.error("Invalid Portal Token");
        }
    }, [token]);

    const handleRatingClick = (setter: React.Dispatch<React.SetStateAction<number>>, val: number) => {
        setter(val);
    };

    const handleSubmit = () => {
        if (rating === 0 || quality === 0 || timeliness === 0 || communication === 0) {
            alert("Please provide all ratings before submitting.");
            return;
        }

        const feedback: CustomerFeedback = {
            rating,
            quality,
            timeliness,
            communication,
            comments,
            submittedAt: new Date().toISOString()
        };

        // Create the Signed Verification Token
        const verificationData = {
            code: projectData?.code,
            feedback
        };
        const encoded = btoa(JSON.stringify(verificationData));
        setSignedCode(encoded);
        setIsSubmitted(true);
    };

    const StarRating = ({ value, label, onSelect }: { value: number; label: string; onSelect: (v: number) => void }) => (
        <div className="flex flex-col gap-2 mb-6">
            <div className="flex justify-between items-center">
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">{label}</span>
                <span className="text-xs font-bold text-blue-600">{value}/5</span>
            </div>
            <div className="flex gap-2">
                {[1, 2, 3, 4, 5].map((star) => (
                    <button
                        key={star}
                        onClick={() => onSelect(star)}
                        className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center text-lg ${
                            star <= value 
                                ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20 scale-105' 
                                : 'bg-slate-100 text-slate-300 hover:bg-slate-200'
                        }`}
                    >
                        <Icon name="fas fa-star" />
                    </button>
                ))}
            </div>
        </div>
    );

    if (!projectData) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 text-center">
                <div className="space-y-4 max-w-sm">
                    <Icon name="fas fa-exclamation-triangle" className="text-5xl text-amber-500 mb-4" />
                    <h2 className="text-2xl font-black uppercase tracking-tighter">Portal Link Invalid</h2>
                    <p className="text-slate-500 text-sm">The feedback session has expired or the link provided is corrupt. Please contact your AEWorks Project Lead.</p>
                </div>
            </div>
        );
    }

    if (isSubmitted) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 text-center animate-fade-in">
                <div className="bg-white p-8 rounded-[3rem] shadow-2xl border border-slate-100 max-w-md w-full space-y-8">
                    <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-3xl mx-auto shadow-inner">
                        <Icon name="fas fa-check" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black uppercase tracking-tighter text-slate-900 leading-none">Feedback Signed</h2>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">Verification Protocol Initialized</p>
                    </div>
                    <div className="bg-slate-900 p-6 rounded-3xl text-white space-y-4">
                        <p className="text-xs opacity-70">Please copy the secure verification code below and send it to your project lead to authorize final closeout.</p>
                        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 break-all font-mono text-[10px] font-bold text-blue-400 select-all">
                            {signedCode}
                        </div>
                        <Button 
                            onClick={() => {
                                navigator.clipboard.writeText(signedCode);
                                alert("Verification Code copied!");
                            }}
                            variant="primary"
                            icon="fas fa-copy"
                            className="w-full py-4 uppercase text-[10px] tracking-widest"
                        >
                            Copy Signed Code
                        </Button>
                    </div>
                    <p className="text-[10px] text-slate-400 uppercase tracking-[0.2em]">Thank you for partnering with AEWorks.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 md:p-12 animate-fade-in">
            <div className="bg-white rounded-[3rem] shadow-2xl border border-slate-100 max-w-2xl w-full overflow-hidden flex flex-col">
