import React, { useState, useEffect } from 'react';
import Icon from '../ui/Icon';
import Button from '../ui/Button';
import { CustomerFeedback } from '../../types';

interface PublicFeedbackPortalProps {
    token: string;
}

// Placeholder for the Google Apps Script Web App URL provided by the user.
// In a real scenario, this would be injected or stored in a global setting.
const RELAY_URL = "https://script.google.com/macros/s/AKfycbx_placeholder_URL/exec";

const PublicFeedbackPortal: React.FC<PublicFeedbackPortalProps> = ({ token }) => {
    const [projectData, setProjectData] = useState<{ name: string; code: string; value: number } | null>(null);
    const [step, setStep] = useState(1);
    const [rating, setRating] = useState(0);
    const [quality, setQuality] = useState(0);
    const [timeliness, setTimeliness] = useState(0);
    const [communication, setCommunication] = useState(0);
    const [comments, setComments] = useState('');
    const [isSubmitted, setIsSubmitted] = useState(false);
    const [isSending, setIsSending] = useState(false);
    const [signedCode, setSignedCode] = useState('');

    useEffect(() => {
        try {
            // Token is Base64 encoded: "PROJECT_CODE|PROJECT_NAME|VALUE"
            const decoded = atob(token);
            const [code, name, value] = decoded.split('|');
            setProjectData({ code, name, value: parseFloat(value) || 0 });
        } catch (e) {
            console.error("Invalid Portal Token");
        }
    }, [token]);

    const handleSubmit = async () => {
        if (rating === 0 || quality === 0 || timeliness === 0 || communication === 0) {
            alert("Please provide all ratings before signing off.");
            return;
        }

        setIsSending(true);

        const feedback: CustomerFeedback = {
            rating,
            quality,
            timeliness,
            communication,
            comments,
            submittedAt: new Date().toISOString()
        };

        const payload = {
            code: projectData?.code,
            feedback
        };

        try {
            // Attempt automated submission via relay script
            // Using no-cors if it's a simple script that doesn't return headers, 
            // but usually GAS Web Apps work better with standard fetch if configured correctly.
            await fetch(RELAY_URL, {
                method: 'POST',
                mode: 'no-cors',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });

            // Generate manual fallback token just in case
            const encoded = btoa(JSON.stringify(payload));
            setSignedCode(encoded);
            setIsSubmitted(true);
        } catch (e) {
            console.error("Automated submission failed, falling back to manual token.");
            const encoded = btoa(JSON.stringify(payload));
            setSignedCode(encoded);
            setIsSubmitted(true);
        } finally {
            setIsSending(false);
        }
    };

    const StarRating = ({ value, label, onSelect }: { value: number; label: string; onSelect: (v: number) => void }) => (
        <div className="flex flex-col gap-2 mb-6">
            <div className="flex justify-between items-center">
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">{label}</span>
                <span className="text-xs font-bold text-blue-600">{value}/5</span>
            </div>
            <div className="flex gap-2">
                {[1, 2, 3, 4, 5].map((star) => (
                    <button
                        key={star}
                        onClick={() => onSelect(star)}
                        className={`w-10 h-10 md:w-12 md:h-12 rounded-xl transition-all flex items-center justify-center text-lg ${
                            star <= value 
                                ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20 scale-105' 
                                : 'bg-slate-100 text-slate-300 hover:bg-slate-200'
                        }`}
                    >
                        <Icon name="fas fa-star" />
                    </button>
                ))}
            </div>
        </div>
    );

    if (!projectData) {
        return (
            <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 text-center">
                <div className="space-y-6 max-w-sm">
                    <div className="w-20 h-20 bg-red-500/10 text-red-500 rounded-3xl flex items-center justify-center text-3xl mx-auto border border-red-500/20">
                        <Icon name="fas fa-shield-virus" />
                    </div>
                    <h2 className="text-2xl font-black uppercase tracking-tighter text-white">Handover Link Expired</h2>
                    <p className="text-slate-400 text-sm leading-relaxed">The secure project acceptance portal is no longer active for this session. Please contact AEWorks Logistics for a fresh authorization link.</p>
                    <div className="pt-4">
                        <div className="h-px bg-slate-800 w-full mb-4"></div>
                        <p className="text-[9px] font-black text-slate-600 uppercase tracking-[0.4em]">AEWorks Security Layer v4.6</p>
                    </div>
                </div>
            </div>
        );
    }

    if (isSubmitted) {
        return (
            <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 text-center animate-fade-in">
                <div className="bg-white p-8 md:p-12 rounded-[3.5rem] shadow-2xl max-w-md w-full space-y-8 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/10 blur-3xl rounded-full"></div>
                    <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto shadow-inner border border-emerald-100">
                        <Icon name="fas fa-file-signature" />
                    </div>
                    <div>
                        <h2 className="text-3xl font-black uppercase tracking-tighter text-slate-900 leading-none">Accepted & Signed</h2>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-3">Final Project Handover Authorized</p>
                    </div>

                    <div className="bg-slate-900 p-6 rounded-[2rem] text-white space-y-4">
                        <p className="text-xs text-slate-400 font-medium leading-relaxed">Your project feedback has been transmitted to our engineering team. If you need immediate assistance, please provide the <span className="text-blue-400 font-bold">Verification Token</span> below to your project lead.</p>
                        <div className="bg-slate-950/50 p-4 rounded-2xl border border-slate-800 break-all font-mono text-[9px] font-bold text-emerald-400 select-all leading-tight">
                            {signedCode}
                        </div>
                        <Button 
                            onClick={() => {
                                navigator.clipboard.writeText(signedCode);
                                alert("Verification Token copied to clipboard.");
                            }}
                            variant="primary"
                            icon="fas fa-copy"
                            className="w-full py-4 uppercase text-[11px] font-black tracking-widest shadow-xl shadow-blue-500/20"
                        >
                            Copy Signed Token
                        </Button>
                    </div>

                    <div className="pt-4 border-t border-slate-100">
                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-none">Thank you for your business.</p>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-4 md:p-12 animate-fade-in font-sans">
            <div className="bg-white rounded-[3.5rem] shadow-2xl max-w-3xl w-full overflow-hidden flex flex-col relative">

                {/* Steps Indicator */}
                <div className="absolute top-8 left-1/2 -translate-x-1/2 flex gap-2 z-10">
                    <div className={`h-1.5 w-8 rounded-full transition-all ${step >= 1 ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
                    <div className={`h-1.5 w-8 rounded-full transition-all ${step >= 2 ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
                    <div className={`h-1.5 w-8 rounded-full transition-all ${step >= 3 ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
                </div>

                <header className="bg-slate-900 pt-16 pb-12 px-8 md:px-12 text-white flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="flex items-center gap-5">
                        <div className="w-14 h-14 bg-white p-2.5 rounded-[1.2rem] flex items-center justify-center shadow-2xl shrink-0 rotate-3">
                            <Icon name="fas fa-industry" className="text-slate-900 text-3xl" />
                        </div>
                        <div className="text-center md:text-left">
                            <h1 className="text-2xl font-black uppercase tracking-tighter leading-none">Client Handover</h1>
                            <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-40 mt-2">Verified Acceptance Protocol</p>
                        </div>
                    </div>
                    <div className="text-center md:text-right bg-blue-600/20 px-6 py-3 rounded-[1.5rem] border border-blue-500/20">
                        <p className="text-[9px] font-black text-blue-400 uppercase tracking-widest mb-1">Contract Settlement Sum</p>
                        <p className="text-2xl font-black tracking-tighter">₦{projectData.value.toLocaleString()}</p>
                    </div>
                </header>

                <main className="p-8 md:p-16 space-y-10 flex-grow">
                    {step === 1 && (
                        <div className="space-y-8 animate-fade-in">
                            <div className="border-b border-slate-100 pb-6">
                                <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Project Identity</h2>
                                <h3 className="text-4xl font-black text-slate-900 tracking-tighter uppercase leading-none">{projectData.name}</h3>
                                <p className="text-xs font-bold text-blue-600 mt-2 font-mono">CODE: {projectData.code}</p>
                            </div>

                            <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100">
                                <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-4">Contract Validation</h4>
                                <p className="text-sm text-slate-600 leading-relaxed font-medium">
                                    By proceeding, you acknowledge that the works defined for <strong className="text-slate-900">{projectData.name}</strong> have been completed to your satisfaction and the final agreed contract value of <strong className="text-blue-600">₦{projectData.value.toLocaleString()}</strong> is recognized.
                                </p>
                                <Button onClick={() => setStep(2)} variant="primary" className="mt-8 px-12 py-5 uppercase text-[11px] font-black tracking-widest rounded-2xl shadow-xl shadow-blue-500/20 w-full md:w-auto">Confirm & Rate Experience</Button>
                            </div>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="space-y-8 animate-fade-in">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-2">
                                <StarRating value={rating} label="Overall Satisfaction" onSelect={setRating} />
                                <StarRating value={quality} label="Fabrication Finish" onSelect={setQuality} />
                                <StarRating value={timeliness} label="Project Timeliness" onSelect={setTimeliness} />
                                <StarRating value={communication} label="Account Communication" onSelect={setCommunication} />
                            </div>

                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Comments & Site Notes</label>
                                <textarea 
                                    value={comments}
                                    onChange={(e) => setComments(e.target.value)}
                                    rows={4}
                                    placeholder="Tell us about the installation and quality..."
                                    className="w-full p-6 bg-slate-50 border border-slate-200 rounded-[2rem] text-sm outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium text-slate-700 placeholder:text-slate-300"
                                />
                            </div>

                            <div className="flex flex-col md:flex-row gap-4 pt-6">
                                <button onClick={() => setStep(1)} className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-all">Back</button>
                                <Button onClick={() => setStep(3)} variant="primary" className="flex-grow py-5 uppercase text-[11px] font-black tracking-widest rounded-2xl shadow-xl shadow-blue-500/20">Finalize Signature</Button>
                            </div>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-8 animate-fade-in">
                            <div className="bg-blue-900 p-8 md:p-12 rounded-[3rem] text-white relative overflow-hidden shadow-2xl">
                                <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500/20 blur-[100px]"></div>
                                <h4 className="text-xl font-black uppercase tracking-tighter mb-4 flex items-center gap-3">
                                    <Icon name="fas fa-lock" className="text-blue-400" />
                                    Security Signature
                                </h4>
                                <p className="text-sm text-blue-100 font-medium leading-relaxed mb-10 max-w-lg">
                                    You are about to digitally sign the acceptance document for <strong className="text-white">{projectData.code}</strong>. 
                                    This will authorize the AEWorks engineering team to close out the financial ledger for this project.
                                </p>

                                <div className="flex flex-col md:flex-row items-center gap-6">
                                    <Button 
                                        onClick={handleSubmit} 
                                        variant="success" 
                                        size="lg" 
                                        disabled={isSending}
                                        icon={isSending ? "fas fa-sync animate-spin" : "fas fa-stamp"} 
                                        className="w-full md:w-auto px-12 py-5 uppercase text-[11px] font-black tracking-widest bg-emerald-500 hover:bg-emerald-600 border-none shadow-2xl shadow-emerald-900/50"
                                    >
                                        {isSending ? 'Transmitting Signature...' : 'Sign & Authorized Closeout'}
                                    </Button>
                                    {!isSending && <button onClick={() => setStep(2)} className="text-[10px] font-black uppercase tracking-[0.2em] opacity-60 hover:opacity-100 transition-all">Modify Details</button>}
                                </div>
                            </div>
                        </div>
                    )}
                </main>

                <footer className="p-8 text-center bg-slate-50 border-t border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.5em]">AEWorks Enterprise Handover Protocol v4.6 • Secure Vault</p>
                </footer>
            </div>
        </div>
    );
};

export default PublicFeedbackPortal;

import React, { useState, useMemo } from 'react';
import { View, Project } from '../../types';
import { useProjectContext } from '../../hooks/useProjectContext';
import { STATUS_STAGES } from '../../constants';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import * as db from '../../services/db';
import { useAppContext } from '../../hooks/useAppContext';
import { calculateProjectCost } from '../../services/costingService';
import StageDetailsModal from './StageDetailsModal';

interface ProjectTrackerBoardProps {
    setView: (view: View) => void;
}

const ProjectTrackerBoard: React.FC<ProjectTrackerBoardProps> = ({ setView }) => {
    const { projects, setProjects, setCurrentProject, contacts, framingMaterials, finishMaterials, updateProject } = useProjectContext();
    const { showNotification } = useAppContext();
    const [filterText, setFilterText] = useState('');
    const [filterMgr, setFilterMgr] = useState('');

    // State for stage details modal
    const [selectedStageProject, setSelectedStageProject] = useState<Project | null>(null);

    const handleOpenProject = (project: Project) => {
        setCurrentProject(project);
        setView(View.DASHBOARD);
        showNotification(`Loaded ${project.projectCode}`);
    };

    const handleOpenStageDetails = (project: Project) => {
        setSelectedStageProject(project);
    };

    const handleSaveStageDetails = (updatedProject: Project) => {
        updateProject(updatedProject);
    };

    const handleMoveStage = (project: Project, direction: 'prev' | 'next') => {
        const currentStageIndex = STATUS_STAGES.findIndex(s => s.value === parseInt(project.projectStatus));
        if (currentStageIndex === -1) return;

        let nextIndex = direction === 'next' ? currentStageIndex + 1 : currentStageIndex - 1;

        if (nextIndex < 0 || nextIndex >= STATUS_STAGES.length) return;

        const nextStage = STATUS_STAGES[nextIndex];
        const updatedProject = { ...project, projectStatus: nextStage.value.toString(), savedAt: new Date().toISOString(), updatedAt: new Date().toISOString() };

        updateProject(updatedProject);
        showNotification(`Moved ${project.projectCode} to ${nextStage.name}`);
    };

    const getDaysRemaining = (deadline?: string) => {
        if (!deadline) return null;
        const diff = new Date(deadline).getTime() - new Date().getTime();
        const days = Math.ceil(diff / (1000 * 60 * 60 * 24));
        return days;
    };

    const filteredProjects = useMemo(() => {
        return projects.filter(p => {
            const matchesText = (
                (p.projName || '').toLowerCase().includes(filterText.toLowerCase()) ||
                (p.projectCode || '').toLowerCase().includes(filterText.toLowerCase()) ||
                (p.clientName || '').toLowerCase().includes(filterText.toLowerCase())
            );
            const matchesMgr = filterMgr ? p.projMgr === filterMgr : true;
            return matchesText && matchesMgr;
        });
    }, [projects, filterText, filterMgr]);

    const formatMoney = (n: number) => `₦${(n || 0).toLocaleString(undefined, { maximumFractionDigits: 0 })}`;

    const getProjectValue = (project: Project) => {
        if (project.trackingData?.projectValue) {
            return project.trackingData.projectValue;
        }
        try {
            const cost = calculateProjectCost(project, framingMaterials, finishMaterials);
            return cost.salesPrice || 0;
        } catch (e) {
            return 0;
        }
    };

    const FeedbackIndicator = ({ status }: { status?: string }) => {
        if (!status || status === 'none') return null;

        const config: Record<string, { icon: string, color: string, label: string, pulse: boolean, bg: string }> = {
            requested: { icon: 'fa-paper-plane', color: 'text-blue-500', label: 'Handover Sent', pulse: true, bg: 'bg-blue-50' },
            received: { icon: 'fa-envelope-open-text', color: 'text-amber-500', label: 'Review Recieved', pulse: true, bg: 'bg-amber-50' },
            verified: { icon: 'fa-shield-check', color: 'text-emerald-500', label: 'Verified sign-off', pulse: false, bg: 'bg-emerald-50' }
        };

        const c = config[status] || config.requested;

        return (
            <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full border border-current/10 ${c.bg} ${c.color} ${c.pulse ? 'animate-pulse' : ''}`} title={c.label}>
                <Icon name={`fas ${c.icon}`} className="text-[10px]" />
                <span className="text-[8px] font-black uppercase tracking-tighter">{c.label}</span>
            </div>
        );
    };

    return (
        <div className="flex flex-col h-full overflow-hidden bg-slate-100 rounded-lg shadow-inner">
            <header className="bg-white p-3 md:p-4 border-b border-slate-200 flex flex-col gap-3 shadow-sm z-10">
                <div className="flex justify-between items-center">
                    <div className="flex items-center gap-3">
                        <Button onClick={() => setView(View.DASHBOARD)} variant="outline" size="sm" icon="fas fa-arrow-left">
                            <span className="hidden md:inline">Editor</span>
                        </Button>
                        <div>
                            <h2 className="text-lg md:text-2xl font-bold text-slate-800 flex items-center gap-2">
                                <Icon name="fas fa-columns" className="text-blue-600"/> 
                                <span className="hidden md:inline">Project Tracker</span>
                                <span className="md:hidden">Tracker</span>
                            </h2>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden lg:flex gap-4 text-[9px] font-black text-slate-400 uppercase tracking-widest border-r pr-4 border-slate-100">
                             <div className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div> Handover Sent</div>
                             <div className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div> Review Pending</div>
                             <div className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div> Verified</div>
                        </div>
                        <div className="text-xs md:text-sm text-slate-500 font-black uppercase tracking-tighter">
                            {filteredProjects.length} Projects
                        </div>
                    </div>
                </div>

                <div className="flex flex-col md:flex-row gap-2 w-full">
                    <div className="relative flex-grow">
                        <Icon name="fas fa-search" className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="text" 
                            placeholder="Search projects by name, code or client..." 
                            value={filterText}
                            onChange={(e) => setFilterText(e.target.value)}
                            className="pl-9 pr-3 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 w-full text-sm font-bold bg-slate-50"
                        />
                    </div>
                    <select 
                        value={filterMgr} 
                        onChange={(e) => setFilterMgr(e.target.value)}
                        className="py-2 px-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 text-sm font-bold bg-slate-50 w-full md:w-auto"
                    >
                        <option value="">All Managers</option>
                        {contacts.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    </select>
                </div>
            </header>

            {/* Main Board Area */}
            <div className="flex-grow overflow-x-auto overflow-y-hidden p-2 md:p-6 bg-slate-100">
                <div className="flex h-full gap-3 md:gap-5 min-w-max pb-2">
                    {STATUS_STAGES.map((stage) => {
                        const stageProjects = filteredProjects.filter(p => parseInt(p.projectStatus) === stage.value);
                        const stageTotalValue = stageProjects.reduce((acc, curr) => acc + getProjectValue(curr), 0);

                        return (
                            <div key={stage.value} className="flex flex-col w-72 md:w-80 bg-slate-200/50 rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-shadow h-full max-h-full border border-slate-300">
                                {/* Column Header */}
                                <div className={`p-3 bg-white border-t-4 ${stage.color} shadow-sm z-10 flex flex-col gap-1`}>
                                    <div className="flex justify-between items-center">
                                        <span className="font-black text-slate-800 uppercase text-xs tracking-wider truncate pr-2" title={stage.name}>{stage.name}</span>
                                        <span className="bg-slate-950 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{stageProjects.length}</span>
                                    </div>
                                    <div className="text-[10px] text-slate-400 font-black uppercase tracking-tighter text-right">
                                        {stageTotalValue > 0 ? formatMoney(stageTotalValue) : '-'}
                                    </div>
                                </div>

                                {/* Column Content */}
                                <div className="flex-grow overflow-y-auto p-3 space-y-3 custom-scrollbar bg-slate-50/50">
                                    {stageProjects.length === 0 ? (
                                        <div className="flex flex-col items-center justify-center h-40 text-slate-300 opacity-50 select-none">
                                            <Icon name="fas fa-clipboard-list" className="text-3xl mb-2"/>
                                            <p className="text-[10px] font-black uppercase tracking-widest">Board Empty</p>
                                        </div>
                                    ) : (
                                        stageProjects.map(project => {
                                            const daysLeft = getDaysRemaining(project.deadline);
                                            const projValue = getProjectValue(project);
                                            const fStatus = project.trackingData?.feedbackStatus;

                                            let deadlineClass = "text-slate-500";
                                            if (daysLeft !== null) {
                                                if (daysLeft < 0) deadlineClass = "text-red-600 font-black";
                                                else if (daysLeft <= 3) deadlineClass = "text-amber-600 font-black";
                                                else deadlineClass = "text-emerald-600 font-black";
                                            }

                                            return (
                                                <div key={project.projectCode} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 hover:shadow-xl hover:border-blue-400 transition-all group relative flex flex-col gap-3">

                                                    <div className="flex justify-between items-start">
                                                        <span className="font-mono text-[9px] font-black bg-slate-900 px-2 py-0.5 rounded text-slate-100 uppercase tracking-tighter truncate max-w-[120px]">{project.projectCode}</span>
                                                        <div className="flex flex-col items-end gap-1">
                                                            <FeedbackIndicator status={fStatus} />
                                                            {projValue > 0 && (
                                                                <span className="text-[10px] font-black text-slate-900 mt-1">
                                                                    {formatMoney(projValue)}
                                                                </span>
                                                            )}
                                                        </div>
                                                    </div>

                                                    <div>
                                                        <h4 className="font-black text-slate-900 text-xs leading-tight mb-1 line-clamp-2 uppercase tracking-tight" title={project.projName}>{project.projName || 'Untitled Project'}</h4>
                                                        <div className="text-[10px] font-bold text-slate-400 truncate uppercase tracking-tighter" title={project.clientName}>
                                                            {project.clientName || 'Private Client'}
                                                        </div>
                                                    </div>

                                                    <div className="grid grid-cols-2 gap-1 text-[9px] font-black uppercase tracking-tighter">
                                                        <div className="bg-slate-50 p-1.5 rounded-lg flex items-center gap-1.5 truncate border border-slate-100" title={`Lead: ${project.projMgr}`}>
                                                            <Icon name="fas fa-user-circle" className="text-blue-500"/> 
                                                            <span className="truncate text-slate-600">{project.projMgr || '-'}</span>
                                                        </div>
                                                        <div className={`bg-slate-50 p-1.5 rounded-lg flex items-center gap-1.5 truncate border border-slate-100 ${deadlineClass}`} title="Deadline Status">
                                                            <Icon name="fas fa-calendar-check"/>
                                                            <span>{daysLeft !== null ? (daysLeft < 0 ? `${Math.abs(daysLeft)}d late` : `${daysLeft}d rem`) : '-'}</span>
                                                        </div>
                                                    </div>

                                                    <div className="flex justify-between items-center pt-2 border-t border-slate-50 mt-1">
                                                        <button 
                                                            onClick={(e) => { e.stopPropagation(); handleMoveStage(project, 'prev'); }} 
                                                            disabled={stage.value === 0}
                                                            className="text-slate-300 hover:text-blue-600 disabled:opacity-20 transition-all p-1"
                                                        >
                                                            <Icon name="fas fa-chevron-left"/>
                                                        </button>

                                                        <div className="flex gap-1.5">
                                                            <button 
                                                                onClick={(e) => { e.stopPropagation(); handleOpenStageDetails(project); }}
                                                                className="text-[9px] font-black uppercase tracking-widest bg-slate-900 text-white hover:bg-blue-600 px-3 py-1.5 rounded-lg transition-all flex items-center gap-1.5 shadow-sm"
                                                            >
                                                                <Icon name="fas fa-shield-alt" className="text-[8px] text-blue-400"/> Info
                                                            </button>
                                                            <button 
                                                                onClick={(e) => { e.stopPropagation(); handleOpenProject(project); }}
                                                                className="text-[9px] font-black uppercase tracking-widest bg-slate-100 text-slate-500 hover:bg-slate-200 px-3 py-1.5 rounded-lg transition-all"
                                                            >
                                                                Open
                                                            </button>
                                                        </div>

                                                        <button 
                                                            onClick={(e) => { e.stopPropagation(); handleMoveStage(project, 'next'); }} 
                                                            disabled={stage.value === 100}
                                                            className="text-slate-300 hover:text-blue-600 disabled:opacity-20 transition-all p-1"
                                                        >
                                                            <Icon name="fas fa-chevron-right"/>
                                                        </button>
                                                    </div>
                                                </div>
                                            );
                                        })
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Stage Details Modal */}
            {selectedStageProject && (
                <StageDetailsModal 
                    isOpen={!!selectedStageProject} 
                    onClose={() => setSelectedStageProject(null)} 
                    project={selectedStageProject}
                    onSave={handleSaveStageDetails}
                />
            )}
        </div>
    );
};

export default ProjectTrackerBoard;

import React, { useState, useEffect } from 'react';
import Modal from '../ui/Modal';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { Project, ProjectTrackingData, CustomerFeedback, WorkerEvaluation, Contact } from '../../types';
import { calculateProjectCost } from '../../services/costingService';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface StageDetailsModalProps {
    isOpen: boolean;
    onClose: () => void;
    project: Project;
    onSave: (updatedProject: Project) => void;
}

const StageDetailsModal: React.FC<StageDetailsModalProps> = ({ isOpen, onClose, project, onSave }) => {
    const { framingMaterials, finishMaterials, contacts, setContacts } = useProjectContext();
    const { currentUser, showNotification } = useAppContext();
    const [formData, setFormData] = useState<ProjectTrackingData>({});
    const [verificationToken, setVerificationToken] = useState('');
    const [workerRatings, setWorkerRatings] = useState<Record<string, number>>({});
    const [showVerificationInput, setShowVerificationInput] = useState(false);

    // Derived data for auto-filling
    const [autoData, setAutoData] = useState({
        calculatedCost: 0,
        calculatedVolume: 0,
        partCountEstimate: 0
    });

    useEffect(() => {
        if (project) {
            setFormData(project.trackingData || {});

            const costs = calculateProjectCost(project, framingMaterials, finishMaterials);
            const vol = (project.shippingLength || 0) * (project.shippingWidth || 0) * (project.shippingHeight || 0);
            const parts = project.jobs.reduce((acc, job) => acc + job.framingTakeOff.reduce((jAcc, item) => jAcc + (item.qty || 0), 0), 0);

            setAutoData({
                calculatedCost: costs.salesPrice,
                calculatedVolume: parseFloat(vol.toFixed(3)),
                partCountEstimate: parts
            });

            const initialRatings: Record<string, number> = {};
            project.trackingData?.workerEvaluations?.forEach(ev => {
                initialRatings[ev.workerId] = ev.rating;
            });
            setWorkerRatings(initialRatings);
        }
    }, [project, framingMaterials, finishMaterials]);

    const handleChange = (field: keyof ProjectTrackingData, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleGeneratePortalLink = () => {
        const val = project.useManualValuation && project.manualItems && project.manualItems.length > 0 
            ? project.manualItems.reduce((s, i) => s + (i.amount || 0), 0)
            : autoData.calculatedCost;

        const rawToken = `${project.projectCode}|${project.projName}|${val}`;
        const encoded = btoa(rawToken);
        const url = `${window.location.origin}${window.location.pathname}?p_feedback=${encoded}`;

        navigator.clipboard.writeText(url);
        handleChange('feedbackStatus', 'requested');
        showNotification("Handover Portal Link copied to clipboard.", "success");
    };

    const handleVerifyToken = () => {
        if (!verificationToken.trim()) return;
        try {
            const decoded = JSON.parse(atob(verificationToken.trim()));
            if (decoded.code !== project.projectCode) {
                alert("Security Error: This token is linked to a different project code.");
                return;
            }

            // Auto-Import Feedback Data
            setFormData(prev => ({ 
                ...prev, 
                customerFeedback: decoded.feedback,
                feedbackStatus: 'received' // Awaiting worker confirmation
            }));
            setVerificationToken('');
            setShowVerificationInput(false);
            showNotification("Manual token validated. Please review and confirm the feedback.");
        } catch (e) {
            alert("Invalid Security Token. Please ensure the full string was pasted.");
        }
    };

    const handleWorkerConfirmFeedback = () => {
        if (!formData.customerFeedback) return;

        const updatedFeedback: CustomerFeedback = {
            ...formData.customerFeedback,
            verifiedAt: new Date().toISOString(),
            verifiedBy: currentUser?.username || 'Authorized Admin'
        };

        setFormData(prev => ({ 
            ...prev, 
            customerFeedback: updatedFeedback,
            feedbackStatus: 'verified' 
        }));

        showNotification("Acceptance Protocol Verified. Final Project Closeout AUTHORIZED.");
    };

    const handleUpdateWorkerRating = (workerId: string, rating: number) => {
        setWorkerRatings(prev => ({ ...prev, [workerId]: rating }));
    };

    const handleSave = () => {
        const workerEvaluations: WorkerEvaluation[] = Object.entries(workerRatings).map(([workerId, rating]) => ({
            workerId,
            rating
        }));

        // Push ratings to global contact registry
        if (workerEvaluations.length > 0 && formData.feedbackStatus === 'verified') {
            const currentContacts = db.getData<Contact>('contacts');
            const updatedContacts = currentContacts.map(c => {
                const myEval = workerEvaluations.find(ev => ev.workerId === c.id);
                if (myEval) {
                    const existingRating = c.rating || 5;
                    const newRating = (existingRating + myEval.rating) / 2;
                    return { ...c, rating: parseFloat(newRating.toFixed(1)) };
                }
                return c;
            });
            db.saveData('contacts', updatedContacts);
            setContacts(updatedContacts);
        }

        let newStatus = project.projectStatus;
        const isFullyUnlocked = formData.feedbackStatus === 'verified';

        // Final stage check: If verified and critical boxes are checked, move to 100%
        if (isFullyUnlocked && 
            formData.shipmentApproved && 
            formData.projectSignoff && 
            formData.balanceConfirmed && 
            newStatus !== '100') {
            newStatus = '100';
            showNotification("Project archived successfully.", "success");
        }

        const updatedTrackingData = {
            ...formData,
            projectValue: formData.projectValue || autoData.calculatedCost,
            workerEvaluations
        };

        const updatedProject = { 
            ...project, 
            projectStatus: newStatus,
            trackingData: updatedTrackingData,
            updatedAt: new Date().toISOString()
        };

        onSave(updatedProject);
        onClose();
    };

    const statusValue = parseInt(project.projectStatus);
    const isVerified = formData.feedbackStatus === 'verified';
    const isReceived = formData.feedbackStatus === 'received';

    const ApprovalToggle = ({ label, field, icon, disabled = false }: { label: string, field: keyof ProjectTrackingData, icon: string, disabled?: boolean }) => (
        <div className={`flex items-center justify-between p-3 rounded-2xl border transition-all ${formData[field] ? 'bg-emerald-50 border-emerald-200' : 'bg-white border-slate-100'} ${disabled ? 'opacity-30 grayscale pointer-events-none' : 'hover:border-slate-300'}`}>
            <div className="flex items-center gap-3">
                <div className={`w-9 h-9 rounded-xl flex items-center justify-center ${formData[field] ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20' : 'bg-slate-100 text-slate-400'}`}>
                    <Icon name={icon} />
                </div>
                <span className={`text-[10px] font-black uppercase tracking-tighter ${formData[field] ? 'text-emerald-900' : 'text-slate-500'}`}>{label}</span>
            </div>
            <button 
                disabled={disabled}
                onClick={() => handleChange(field, !formData[field])}
                className={`w-11 h-6 rounded-full relative transition-colors ${formData[field] ? 'bg-emerald-600' : 'bg-slate-200'}`}
            >
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${formData[field] ? 'left-6' : 'left-1'}`}></div>
            </button>
        </div>
    );

    const renderCloseoutStage = () => {
        const assignedWorkers = project.workTeamSpec?.assignedStaffIds?.map(id => contacts.find(c => c.id === id)).filter(Boolean) as Contact[] || [];

        return (
            <div className="animate-fade-in space-y-8 pb-4">
                {/* Protocol Gate View */}
                {!isVerified ? (
                    <div className="bg-slate-950 p-6 md:p-8 rounded-[2.5rem] text-white space-y-6 shadow-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-48 h-48 bg-amber-500/10 blur-[80px]"></div>
                        <div className="flex flex-col md:flex-row items-center gap-6">
                            <div className="w-20 h-20 bg-amber-500/20 text-amber-500 rounded-[1.8rem] flex items-center justify-center text-4xl shrink-0 border border-amber-500/30">
                                <Icon name={isReceived ? "fas fa-envelope-open-text" : "fas fa-lock"} />
                            </div>
                            <div className="text-center md:text-left">
                                <h4 className="text-2xl font-black uppercase tracking-tighter leading-none">{isReceived ? "Feedback Received" : "Operational Lock Active"}</h4>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">Closeout requires verified customer acceptance protocol.</p>
                            </div>
                        </div>

                        {isReceived ? (
                            <div className="bg-white/5 p-6 rounded-[2rem] border border-white/10 animate-fade-in">
                                <div className="flex justify-between items-start mb-6">
                                    <h5 className="text-[10px] font-black text-blue-400 uppercase tracking-[0.2em]">Customer Review Received</h5>
                                    <div className="bg-amber-500 text-slate-900 px-3 py-1 rounded-full text-[9px] font-black uppercase">Pending Internal Confirmation</div>
                                </div>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                                    {[
                                        { l: 'Quality', v: formData.customerFeedback?.quality },
                                        { l: 'Timing', v: formData.customerFeedback?.timeliness },
                                        { l: 'Comm.', v: formData.customerFeedback?.communication },
                                        { l: 'Overall', v: formData.customerFeedback?.rating }
                                    ].map(r => (
                                        <div key={r.l} className="bg-black/30 p-3 rounded-2xl border border-white/5 text-center">
                                            <p className="text-[8px] font-black uppercase text-slate-500 mb-1">{r.l}</p>
                                            <p className="text-xl font-black text-white">{r.v}/5</p>
                                        </div>
                                    ))}
                                </div>
                                <div className="bg-black/50 p-4 rounded-2xl mb-6 text-xs text-slate-300 font-medium italic border-l-4 border-blue-500">
                                    "{formData.customerFeedback?.comments || 'No comment provided.'}"
                                </div>
                                <Button onClick={handleWorkerConfirmFeedback} variant="primary" className="w-full py-4 text-[10px] font-black uppercase tracking-widest bg-emerald-600 hover:bg-emerald-700 shadow-xl shadow-emerald-900/40 border-none">
                                    Confirm Feedback & Unlock Stage
                                </Button>
                            </div>
                        ) : (
                            <div className="flex flex-col gap-3">
                                {showVerificationInput ? (
                                    <div className="space-y-3 animate-fade-in">
                                        <input 
                                            type="text" 
                                            value={verificationToken}
                                            onChange={(e) => setVerificationToken(e.target.value)}
                                            placeholder="Paste Token from Customer (Manual Handshake)..."
                                            className="w-full p-4 bg-slate-900 border border-slate-800 rounded-2xl text-xs font-mono font-bold text-blue-400 outline-none focus:border-blue-500"
                                        />
                                        <div className="flex gap-2">
                                            <Button onClick={handleVerifyToken} variant="primary" className="flex-grow py-3 text-[10px] font-black uppercase tracking-widest">Verify Manual Token</Button>
                                            <button onClick={() => setShowVerificationInput(false)} className="px-6 text-[10px] font-black uppercase text-slate-500">Cancel</button>
                                        </div>
                                    </div>
                                ) : (
                                    <div className="flex flex-col md:flex-row gap-3">
                                        <Button onClick={handleGeneratePortalLink} variant="primary" icon="fas fa-link" className="flex-grow py-4 text-[10px] font-black uppercase tracking-widest">Generate Handover Portal</Button>
                                        <Button onClick={() => setShowVerificationInput(true)} variant="warning" icon="fas fa-key" className="flex-grow py-4 text-[10px] font-black uppercase tracking-widest text-slate-900">Verify Manual Token</Button>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="bg-emerald-950 p-8 rounded-[2.5rem] text-white flex items-center justify-between gap-8 border-l-8 border-emerald-500 shadow-2xl relative overflow-hidden animate-fade-in">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 blur-[100px]"></div>
                        <div className="flex items-center gap-6">
                            <div className="w-20 h-20 bg-emerald-500/20 text-emerald-500 rounded-[1.8rem] flex items-center justify-center text-4xl shrink-0 border border-emerald-500/30 shadow-inner">
                                <Icon name="fas fa-check-double" />
                            </div>
                            <div>
                                <h4 className="text-2xl font-black uppercase tracking-tighter leading-none">Acceptance Verified</h4>
                                <p className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest mt-2 flex items-center gap-2">
                                    <Icon name="fas fa-user-check" /> Verified by {formData.customerFeedback?.verifiedBy} on {new Date(formData.customerFeedback!.verifiedAt!).toLocaleDateString()}
                                </p>
                            </div>
                        </div>
                        <div className="hidden md:block bg-emerald-900/40 p-4 rounded-2xl border border-emerald-800 text-center px-8">
                            <p className="text-[9px] font-black uppercase opacity-60 mb-1">Customer Rating</p>
                            <p className="text-2xl font-black text-emerald-300">{formData.customerFeedback?.rating}.0</p>
                        </div>
                    </div>
                )}

                {/* Operations Checklist */}
                <div className={`grid grid-cols-1 lg:grid-cols-2 gap-8 ${!isVerified ? 'opacity-30 grayscale pointer-events-none' : 'animate-fade-in'}`}>
                    <div className="space-y-4 bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                        <h5 className="text-[11px] font-black uppercase text-slate-400 tracking-widest border-b pb-3 mb-2">Internal Financials</h5>
                        <ApprovalToggle label="Approve Team Disbursal" field="teamPaymentsApproved" icon="fas fa-hand-holding-usd" />
                        <div className="space-y-3">
                            <ApprovalToggle label="Approve Project Bonuses" field="teamBonusesApproved" icon="fas fa-gift" />
                            {formData.teamBonusesApproved && (
                                <div className="pl-4 animate-fade-in">
                                    <label className="block text-[9px] font-black text-slate-400 uppercase mb-2 ml-1">Bonus Pool Value (₦)</label>
                                    <input 
                                        type="number" 
                                        value={formData.teamBonusAmount || ''} 
                                        onChange={(e) => handleChange('teamBonusAmount', parseFloat(e.target.value))}
                                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-blue-600 outline-none focus:border-blue-500"
                                        placeholder="0.00"
                                    />
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="space-y-4 bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                        <h5 className="text-[11px] font-black uppercase text-slate-400 tracking-widest border-b pb-3 mb-2">Dispatch & Compliance</h5>
                        <ApprovalToggle label="Authorize Dispatch" field="shipmentApproved" icon="fas fa-truck-ramp-box" />
                        <ApprovalToggle label="Final Balance Sign-off" field="balanceConfirmed" icon="fas fa-cash-register" />
                        <ApprovalToggle label="Legal Release Mapped" field="projectSignoff" icon="fas fa-file-contract" />
                    </div>
                </div>

                {/* Performance Evaluation */}
                {isVerified && assignedWorkers.length > 0 && (
                    <div className="bg-slate-50 p-8 rounded-[2.5rem] space-y-6 border border-slate-100 animate-fade-in">
                        <div className="flex justify-between items-center border-b border-slate-200 pb-4">
                            <h5 className="text-[11px] font-black uppercase text-slate-500 tracking-widest">Internal Team Performance</h5>
                            <span className="bg-white px-3 py-1 rounded-full text-[10px] font-black text-slate-400 border border-slate-200">{assignedWorkers.length} Personnel Linked</span>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {assignedWorkers.map(worker => (
                                <div key={worker.id} className="p-5 bg-white rounded-2xl border border-slate-100 flex items-center justify-between hover:border-blue-200 transition-all shadow-sm">
                                    <div className="flex items-center gap-4">
                                        <div className="w-12 h-12 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-lg shadow-lg">{worker.name.charAt(0)}</div>
                                        <div>
                                            <p className="text-xs font-black uppercase text-slate-900 leading-none">{worker.name}</p>
                                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">{worker.designation}</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-1.5">
                                        {[1, 2, 3, 4, 5].map(star => (
                                            <button 
                                                key={star}
                                                onClick={() => handleUpdateWorkerRating(worker.id, star)}
                                                className={`text-sm p-1 transition-all ${star <= (workerRatings[worker.id] || 0) ? 'text-amber-500 scale-125' : 'text-slate-100 hover:text-amber-200'}`}
                                            >
                                                <Icon name="fas fa-star" />
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Final Signature Section */}
                <div className={`space-y-4 bg-slate-900 p-8 rounded-[2.5rem] text-white ${!isVerified ? 'opacity-30 grayscale pointer-events-none' : 'animate-fade-in'}`}>
                    <h5 className="text-[11px] font-black uppercase text-blue-400 tracking-[0.2em] mb-4">Final Ledger Audit</h5>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1">Archive Date</label>
                            <input 
                                type="date" 
                                value={formData.finalCloseoutDate || new Date().toISOString().split('T')[0]} 
                                onChange={(e) => handleChange('finalCloseoutDate', e.target.value)} 
                                className="w-full p-4 bg-slate-950 border border-slate-800 rounded-2xl font-black text-white outline-none focus:border-blue-500"
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1">Confirmed Receiver</label>
                            <input 
                                type="text" 
                                value={formData.deliveryConfirmedBy || ''} 
                                onChange={(e) => handleChange('deliveryConfirmedBy', e.target.value)} 
                                className="w-full p-4 bg-slate-950 border border-slate-800 rounded-2xl font-black text-white outline-none focus:border-blue-500 placeholder:text-slate-700"
                                placeholder="Client Contact Name..."
                            />
                        </div>
                    </div>
                    <div className="pt-2">
                        <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1">Site Handover Notes</label>
                        <textarea 
                            rows={3} 
                            value={formData.closeoutNotes || ''} 
                            onChange={(e) => handleChange('closeoutNotes', e.target.value)} 
                            className="w-full p-4 bg-slate-950 border border-slate-800 rounded-2xl text-[11px] font-medium text-slate-300 outline-none focus:border-blue-500"
                            placeholder="Warranties, keys handed over, or site exceptions..."
                        />
                    </div>
                </div>
            </div>
        );
    };

    const getStageContent = () => {
        if (statusValue < 15) return <div className="text-center py-24 text-slate-300 font-black uppercase text-xs tracking-[0.3em]">Project must be 'Started' to access tracking.</div>;
        if (statusValue < 35) return renderStartedStage();
        if (statusValue < 55) return renderProcurementStage();
        if (statusValue < 75) return renderWIPStage();
        if (statusValue < 85) return renderAssemblyStage();
        if (statusValue < 95) return renderPackageStage();
        if (statusValue < 100) return renderShippedStage();
        return renderCloseoutStage();
    };

    const renderStartedStage = () => (
        <div className="space-y-6 animate-fade-in">
             <div className="bg-blue-600 text-white p-6 rounded-[2rem] shadow-xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 blur-2xl"></div>
                <h4 className="text-xs font-black uppercase tracking-widest mb-2 opacity-60">Contract Authorization</h4>
                <p className="text-2xl font-black tracking-tighter">₦{autoData.calculatedCost.toLocaleString()}</p>
                <p className="text-[10px] font-black uppercase tracking-widest mt-2">Calculated Target Quote</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                    <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Deposit Verification Date</label>
                        <input type="date" value={formData.paymentConfDate || ''} onChange={(e) => handleChange('paymentConfDate', e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold" />
                    </div>
                    <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Factory Supervisor Signature</label>
                        <input type="text" value={formData.teamLead || ''} onChange={(e) => handleChange('teamLead', e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold" placeholder="Assigned Team Lead" />
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Amount Committed (₦)</label>
                        <input type="number" value={formData.amountCommitted || ''} onChange={(e) => handleChange('amountCommitted', parseFloat(e.target.value))} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-black text-blue-600" placeholder={`Suggested: ${autoData.calculatedCost * 0.7}`} />
                    </div>
                    <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Accounting Sign-off</label>
                        <input type="text" value={formData.paymentConfirmedBy || ''} onChange={(e) => handleChange('paymentConfirmedBy', e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold" />
                    </div>
                </div>
            </div>
        </div>
    );

    const renderProcurementStage = () => (
        <div className="space-y-6 animate-fade-in">
            <div className="bg-indigo-600 text-white p-6 rounded-[2rem] shadow-xl">
                <h4 className="text-[10px] font-black uppercase tracking-[0.2em] mb-4">Stock Allocation Protocol</h4>
                <div className="space-y-2">
                    <label className="text-[9px] font-black uppercase opacity-60">Supply Chain Lead</label>
                    <input type="text" value={formData.purchaserInfo || ''} onChange={(e) => handleChange('purchaserInfo', e.target.value)} className="w-full p-3 bg-indigo-500/30 border border-white/20 rounded-xl font-black text-white outline-none focus:border-white" />
                </div>
            </div>
            <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Material Batch Details</label>
                <textarea rows={8} value={formData.purchaseList || ''} onChange={(e) => handleChange('purchaseList', e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm text-slate-700 outline-none focus:border-indigo-500" placeholder="Specify bulk material orders or specialized section requirements..." />
            </div>
        </div>
    );

    const renderWIPStage = () => (
        <div className="space-y-6 animate-fade-in">
             <div className="bg-slate-950 p-6 rounded-[2rem] text-white flex justify-between items-center shadow-2xl">
                <div>
                    <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Theoretical Part Count</span>
                    <div className="text-3xl font-black tracking-tighter text-blue-400">{autoData.partCountEstimate}</div>
                </div>
                <div className="text-right">
                    <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Scope Density</span>
                    <div className="flex gap-1.5 mt-2">
                        {[1,2,3,4,5].map(i => (
                            <div key={i} className={`w-3 h-8 rounded-full transition-all ${(formData.partComplexity || 0) >= i ? 'bg-blue-500 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-800'}`}></div>
                        ))}
                    </div>
                </div>
            </div>
            <div className="grid grid-cols-2 gap-6">
                <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Actual Part Log</label>
                    <input type="number" value={formData.partCount || ''} onChange={(e) => handleChange('partCount', parseInt(e.target.value))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xl text-slate-900" />
                </div>
                 <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1">Execution Complexity</label>
