    const [finishMaterials, setFinishMaterials] = useState<FinishMaterial[]>([]);
    const [projects, setProjects] = useState<Project[]>([]);
    const [defaultCostingVariables, setDefaultCostingVariables] = useState<CostingVariables>({});
