    const [portalToken, setPortalToken] = useState<string | null>(null);

    const showNotification = useCallback((message: string, type: 'success' | 'error' | 'warning' = 'success') => {
        setNotification({ message, type });
        setTimeout(() => setNotification(null), 4000);
    }, []);

    // Resilient Background Sync Logic
    useEffect(() => {
        const triggerSync = async () => {
            const meta = db.getSystemMeta();
            if (navigator.onLine && meta.driveAccessToken) {
                console.log("Auto Polling: Checking Cloud Vault & Inbox...");
                try {
                    // Corrected the number of arguments passed to syncWithCloud (was 3, should be 2)
                    await db.syncWithCloud(undefined, (code) => {
                        showNotification(`New Customer Feedback received for ${code}!`, 'warning');
                    });
                } catch (e) {}
            }
        };

        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                triggerSync();
            }
        };

        window.addEventListener('online', triggerSync);
        document.addEventListener('visibilitychange', handleVisibilityChange);

        // Periodic background check (every 2 mins for collaboration and feedback)
        const interval = setInterval(triggerSync, 120000);

        return () => {
            window.removeEventListener('online', triggerSync);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
            clearInterval(interval);
        };
    }, [showNotification]);

    // Initialize Database
    useEffect(() => {
        const initDB = async () => {
            const meta = db.getSystemMeta();
            const existingUsers = db.getData<AuthUser>('users');

            // Check for Portal Token in URL
            const urlParams = new URLSearchParams(window.location.search);
            const token = urlParams.get('p_feedback');
            if (token) {
                setPortalToken(token);
                setActiveModule('feedback-portal');
            }

            // 1. Local Fallback Provisioning
            if (existingUsers.length === 0 && !meta.driveAccessToken) {
                db.saveData('users', INITIAL_USER_DATA as any);
                db.saveData('clients', INITIAL_CLIENTS_DATA as any);
                db.saveData('contacts', INITIAL_CONTACTS_DATA as any);
                db.saveData('centres', INITIAL_CENTRES_DATA as any);
                db.saveData('framingMaterials', INITIAL_FRAMING_DATA as any);
                db.saveData('finishMaterials', INITIAL_FINISH_DATA as any);
            }

            // 2. Silent Cloud Pull on Boot
            if (navigator.onLine && meta.driveAccessToken) {
                try {
                    await db.syncWithCloud();
                } catch (e) {
                    console.warn("Initial sync deferred.");
                }
            }

            setIsInitialized(true);
        };
        initDB();
    }, []);

    const contextValue = useMemo(() => ({
        currentUser,
        setCurrentUser,
        showNotification
    }), [currentUser, showNotification]);

    const handleLogin = (user: User) => {
        setCurrentUser(user);
        setActiveModule('dashboard');
    };

    const renderContent = () => {
        if (activeModule === 'feedback-portal' && portalToken) {
            return <PublicFeedbackPortal token={portalToken} />;
        }

        switch (activeModule) {
            case 'project-board':
            case 'feedback-journal':
                return <MainLayout onBack={() => setActiveModule('dashboard')} />;
            case 'kpi-monitor':
                return <LegacyAppContainer htmlContent={kpiMonitorHtml} title="KPI Monitor" onBack={() => setActiveModule('dashboard')} />;
            case 'payroll-manager':
                return <PayrollManager onBack={() => setActiveModule('dashboard')} onNavigate={setActiveModule} />;
            case 'work-manager':
                return <WorkManager onBack={() => setActiveModule('dashboard')} />;
            case 'dashboard':
            default:
                return <LandingPage onNavigate={setActiveModule} onLogout={() => setCurrentUser(null)} />;
        }
    };

    if (!isInitialized) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-slate-950 text-white">
                <div className="flex flex-col items-center gap-6">
                    <div className="relative">
                        <div className="absolute inset-0 bg-blue-500 blur-2xl opacity-20 animate-pulse"></div>
                        <i className="fas fa-circle-notch animate-spin text-5xl text-blue-500 relative z-10"></i>
                    </div>
                    <div className="text-center animate-pulse">
                        <p className="font-black tracking-[0.4em] text-[10px] uppercase mb-1">Connecting</p>
                        <p className="text-[8px] text-slate-600 font-bold uppercase">AEWorks Secure Vault</p>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <AppContextProvider value={contextValue}>
            {(currentUser || activeModule === 'feedback-portal') ? renderContent() : <LoginModal onLogin={handleLogin} />}
            {notification && <Notification message={notification.message} type={notification.type} />}
        </AppContextProvider>
    );
};

export default App;

export const generateId = () => {
    try {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) {
            return crypto.randomUUID();
        }
    } catch (e) {}
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

export const getData = <T,>(key: string): T[] => {
    try {
        const data = localStorage.getItem(key);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        return [];
    }
};

export const saveData = <T,>(key: string, data: T[]): boolean => {
    try {
        const timestamp = new Date().toISOString();
        const dataWithMeta = data.map(item => {
            if (item && typeof item === 'object') {
                const typed = item as any;
                let stableId = typed.id;
                if (key === 'users') stableId = typed.email || typed.username || typed.id;
                if (key === 'projects') stableId = typed.projectCode || typed.id;
                if (key === 'clients') stableId = typed.name || typed.id;

                return {
                    ...item,
                    id: stableId || generateId(),
                    updatedAt: typed.updatedAt || timestamp
                };
            }
            return item;
        });
        localStorage.setItem(key, JSON.stringify(dataWithMeta));
        window.dispatchEvent(new CustomEvent('aeworks_db_update', { detail: { key } }));
        return true;
    } catch (error) {
        return false;
    }
};

export const getSystemLogo = (): string | null => localStorage.getItem('system_logo');
export const saveSystemLogo = (base64Data: string | null): void => {
    if (base64Data) localStorage.setItem('system_logo', base64Data);
    else localStorage.removeItem('system_logo');
};

export interface SystemMeta {
    id: string;
    versionLabel: string;
    lastCloudSync?: string;
    syncApiKey: string; 
    autoSync: boolean;
    backupLocation?: string;
    driveFileId?: string;
    driveAccessToken?: string;
    googleClientId?: string; 
    connectedEmail?: string;
    driveFileUrl?: string;
    activeCollaborators?: string[];
}

const GLOBAL_ENV_CLIENT_ID = (import.meta as any).env?.VITE_GOOGLE_CLIENT_ID;
const HARDCODED_FALLBACK_ID = '674092109435-96p21r75k1jgr7t1f0l4eohf5c49k23t.apps.googleusercontent.com';
const MASTER_CLIENT_ID = GLOBAL_ENV_CLIENT_ID || HARDCODED_FALLBACK_ID;

export const getSystemMeta = (): SystemMeta => {
    const raw = localStorage.getItem('system_meta');
    const defaultMeta: SystemMeta = { 
        id: 'meta', 
        versionLabel: 'v4.6 Multi-Dev Sync', 
        syncApiKey: '',
        autoSync: true,
        backupLocation: 'Google_Drive_AEWorks',
        googleClientId: MASTER_CLIENT_ID
    };
    if (!raw) return defaultMeta;
    try {
        const data = JSON.parse(raw);
        const meta = Array.isArray(data) ? data[0] : data;
        return { ...defaultMeta, ...meta };
    } catch {
        return defaultMeta;
    }
};

export const updateSystemMeta = (meta: Partial<SystemMeta>): void => {
    const current = getSystemMeta();
    localStorage.setItem('system_meta', JSON.stringify([{ ...current, ...meta }]));
};

export const DB_KEYS = ['clients', 'contacts', 'centres', 'framingMaterials', 'finishMaterials', 'projects', 'users', 'payrollRuns', 'defaultCostingVariables', 'productionLogs', 'locationExpenses'];
const MASTER_FILE_NAME = "AEWORKS_MASTER_VAULT.json";
const INBOX_FOLDER_NAME = "AEWORKS_INBOX";

const getDriveHeaders = (token: string) => ({
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
});

export const syncInboxFeedback = async (onNewFeedback?: (code: string) => void): Promise<{ success: boolean, count: number }> => {
    const meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, count: 0 };

    try {
        console.log("Checking AEWORKS_INBOX for new customer signatures...");
        const folderQuery = encodeURIComponent(`name='${INBOX_FOLDER_NAME}' and mimeType='application/vnd.google-apps.folder' and trashed=false`);
        const folderRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${folderQuery}`, { headers: getDriveHeaders(token) });
        const folderData = await folderRes.json();

        if (!folderData.files || folderData.files.length === 0) {
            console.warn("Folder AEWORKS_INBOX not found on Drive.");
            return { success: true, count: 0 };
        }
        const folderId = folderData.files[0].id;

        const filesQuery = encodeURIComponent(`'${folderId}' in parents and trashed=false`);
        const filesRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${filesQuery}&fields=files(id, name)`, { headers: getDriveHeaders(token) });
        const filesData = await filesRes.json();

        const files = filesData.files || [];
        if (files.length === 0) return { success: true, count: 0 };

        let processedCount = 0;
        const projects = getData<any>('projects');
        let updated = false;

        for (const file of files) {
            try {
                const contentRes = await fetch(`https://www.googleapis.com/drive/v3/files/${file.id}?alt=media`, { headers: getDriveHeaders(token) });
                const feedbackData = await contentRes.json();

                if (!feedbackData.code) continue;

                // AGGRESSIVE FUZZY MATCHING
                const incomingCode = feedbackData.code.trim().toUpperCase();
                const incomingBase = incomingCode.split('.')[0]; // Handle suffix like .26

                const projIdx = projects.findIndex((p: any) => {
                    const localCode = (p.projectCode || '').trim().toUpperCase();
                    const localBase = localCode.split('.')[0];
                    return localCode === incomingCode || localBase === incomingBase;
                });

                if (projIdx > -1) {
                    const project = projects[projIdx];
                    // Always ingest if status is not verified
                    if (project.trackingData?.feedbackStatus !== 'verified') {
                        project.trackingData = {
                            ...(project.trackingData || {}),
                            customerFeedback: feedbackData.feedback,
                            feedbackStatus: 'received'
                        };
                        project.updatedAt = new Date().toISOString();
                        processedCount++;
                        updated = true;
                        if (onNewFeedback) onNewFeedback(project.projectCode);
                    }
                    // Crucial: Delete the file from Drive so it doesn't double-process later
                    await fetch(`https://www.googleapis.com/drive/v3/files/${file.id}`, { method: 'DELETE', headers: getDriveHeaders(token) });
                }
            } catch (e) {
                console.error(`Inbox item error:`, e);
            }
        }

        if (updated) {
            saveData('projects', projects);
            // Push to master cloud immediately so other team members see the "NEW" feedback badge
            await pushToCloud();
        }
        return { success: true, count: processedCount };
    } catch (err) {
        console.error("Inbox check failed:", err);
        return { success: false, count: 0 };
    }
};

export const syncWithCloud = async (providedToken?: string, onNewFeedback?: (code: string) => void): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = providedToken || meta.driveAccessToken;
    if (!token) return { success: false, message: "Drive Auth Required." };

    try {
        const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
        const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id, name, modifiedTime)`, { headers: getDriveHeaders(token) });
        const searchData = await searchRes.json();
        const foundFile = (searchData.files || [])[0];

        if (!foundFile) {
            await pushToCloud();
            return { success: true, message: "New Vault Established." };
        }

        const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${foundFile.id}?alt=media`, { headers: getDriveHeaders(token) });
        const actualData = await fileRes.json();

        DB_KEYS.forEach(key => {
            const local = getData<any>(key);
            const remote = actualData[key] || [];
            const merged = mergeDatasets(key, local, remote);
            localStorage.setItem(key, JSON.stringify(merged));
        });

        updateSystemMeta({ driveFileId: foundFile.id, driveAccessToken: token, lastCloudSync: new Date().toISOString() });

        // Also sync the inbox immediately
        await syncInboxFeedback(onNewFeedback);

        window.dispatchEvent(new CustomEvent('aeworks_db_update', { detail: { key: 'all' } }));

        return { success: true, message: "Vault Synchronized." };
    } catch (err: any) {
        return { success: false, message: "Cloud Sync Error." };
    }
};

export const pushToCloud = async (): Promise<{success: boolean, message: string}> => {
    let meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, message: "Offline." };

    try {
        const fullDB: any = { _meta: { lastPush: new Date().toISOString() } };
        DB_KEYS.forEach(key => fullDB[key] = getData(key));

        const metadata = { name: MASTER_FILE_NAME, mimeType: 'application/json' };
        let fileId = meta.driveFileId;

        if (!fileId) {
            const createRes = await fetch('https://www.googleapis.com/drive/v3/files', {
                method: 'POST', headers: getDriveHeaders(token), body: JSON.stringify(metadata)
            });
            const createData = await createRes.json();
            fileId = createData.id;
            updateSystemMeta({ driveFileId: fileId });
        }

        await fetch(`https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media`, {
            method: 'PATCH', headers: getDriveHeaders(token), body: JSON.stringify(fullDB)
        });

        updateSystemMeta({ lastCloudSync: new Date().toISOString() });
        return { success: true, message: "Cloud Push Success." };
    } catch (err: any) {
        return { success: false, message: "Push Error." };
    }
};

const mergeDatasets = (dbKey: string, local: any[], remote: any[]) => {
    const map = new Map();
    const getStableId = (item: any) => {
        if (dbKey === 'users') return item.email || item.username || item.id;
        if (dbKey === 'projects') return item.projectCode || item.id;
        if (dbKey === 'clients') return item.name || item.id;
        return item.id;
    };
    remote.forEach(i => map.set(getStableId(i), i));
    local.forEach(i => {
        const id = getStableId(i);
        const rem = map.get(id);
        if (!rem || new Date(i.updatedAt || 0) > new Date(rem.updatedAt || 0)) map.set(id, i);
    });
    return Array.from(map.values());
};

import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useAppContext } from '../../hooks/useAppContext';
import Icon from '../ui/Icon';
import * as db from '../../services/db';
import { Project, FramingMaterial, FinishMaterial, ProductionLog, LocationExpense } from '../../types';
import HelpGuideModal from '../modules/HelpGuideModal';
import { calculateProjectCost } from '../../services/costingService';
import Button from '../ui/Button';

declare const Chart: any;

interface LandingPageProps {
    onNavigate: (module: 'project-board' | 'kpi-monitor' | 'payroll-manager' | 'work-manager' | 'feedback-journal') => void;
    onLogout: () => void;
}

const LandingPage: React.FC<LandingPageProps> = ({ onNavigate, onLogout }) => {
    const { currentUser, showNotification } = useAppContext();
    const [stats, setStats] = useState({
        pipelineValue: 0, activeJobs: 0, monthlyBurn: 0, efficiencyIndex: 0, pendingFeedback: 0
    });
    const [recentProjects, setRecentProjects] = useState<Project[]>([]);
    const [isHelpOpen, setIsHelpOpen] = useState(false);
    const [logo] = useState<string | null>(db.getSystemLogo());
    const [meta, setMeta] = useState(db.getSystemMeta());
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCheckingInbox, setIsCheckingInbox] = useState(false);

    const chartInstances = useRef<any[]>([]);

    const refreshDashboardData = useCallback(() => {
        const projects = db.getData<Project>('projects');
        const expenses = db.getData<LocationExpense>('locationExpenses');
        const framing = db.getData<FramingMaterial>('framingMaterials');
        const finish = db.getData<FinishMaterial>('finishMaterials');
        setMeta(db.getSystemMeta());

        // Stats calculation
        const labels: string[] = [];
        const revenueData: number[] = [];
        const burnData: number[] = [];
        const today = new Date();

        for (let i = 5; i >= 0; i--) {
            const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
            labels.push(d.toLocaleString('default', { month: 'short' }));
            const monthStart = new Date(d.getFullYear(), d.getMonth(), 1);
            const monthEnd = new Date(d.getFullYear(), d.getMonth() + 1, 0);

            const monthRev = projects
                .filter(p => parseInt(p.projectStatus) >= 95 && p.updatedAt && new Date(p.updatedAt) >= monthStart && new Date(p.updatedAt) <= monthEnd)
                .reduce((acc, p) => acc + calculateProjectCost(p, framing, finish).salesPrice, 0);

            const monthBurn = expenses
                .filter(e => new Date(e.date) >= monthStart && new Date(e.date) <= monthEnd)
                .reduce((acc, e) => acc + (parseFloat(e.amount.toString()) || 0), 0);

            revenueData.push(monthRev);
            burnData.push(monthBurn);
        }

        const totalPipeline = projects.reduce((acc, p) => acc + calculateProjectCost(p, framing, finish).salesPrice, 0);
        const activeCount = projects.filter(p => parseInt(p.projectStatus) > 0 && parseInt(p.projectStatus) < 100).length;
        const feedbackCount = projects.filter(p => p.trackingData?.feedbackStatus === 'received').length;

        setStats({
            pipelineValue: totalPipeline,
            activeJobs: activeCount,
            monthlyBurn: burnData[5],
            efficiencyIndex: (revenueData[5] > 0) ? (revenueData[5] / (burnData[5] || 1)) : 1.2,
            pendingFeedback: feedbackCount
        });

        setRecentProjects([...projects].sort((a,b) => new Date(b.updatedAt || 0).getTime() - new Date(a.updatedAt || 0).getTime()).slice(0, 4));
        return { labels, revenueData, burnData };
    }, []);

    const handleManualSync = async () => {
        if (!meta.driveAccessToken) {
            showNotification("Please link cloud repository first.", "warning");
            return;
        }
        setIsSyncing(true);
        const res = await db.syncWithCloud();
        setIsSyncing(false);
        if (res.success) {
            showNotification("Vault Synchronized.");
            refreshDashboardData();
        } else {
            showNotification(res.message, "error");
        }
    };

    const handleCheckInbox = async () => {
        if (!meta.driveAccessToken) return;
        setIsCheckingInbox(true);
        const res = await db.syncInboxFeedback((code) => {
            showNotification(`New feedback ingested for ${code}`, "success");
        });
        setIsCheckingInbox(false);
        if (res.success) {
            if (res.count > 0) {
                showNotification(`Found ${res.count} new customer signatures!`, "success");
                refreshDashboardData();
            } else {
                showNotification("Inbox is empty. No new signatures.", "default");
            }
        }
    };

    useEffect(() => {
        const { labels, revenueData, burnData } = refreshDashboardData();
        window.addEventListener('aeworks_db_update', refreshDashboardData);

        if (document.getElementById('profitChart')) {
            const ctx = (document.getElementById('profitChart') as HTMLCanvasElement).getContext('2d');
            if (ctx) {
                chartInstances.current.push(new Chart(ctx, {
                    type: 'bar',
                    data: {
                        labels,
                        datasets: [
                            { label: 'Revenue', data: revenueData, backgroundColor: '#3b82f6', borderRadius: 8 },
                            { label: 'Burn', data: burnData, backgroundColor: '#f87171', borderRadius: 8 }
                        ]
                    },
                    options: { 
                        responsive: true, maintainAspectRatio: false, 
