import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
    onHome?: () => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView, onHome }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, setCurrentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCommitting, setIsCommitting] = useState(false);
    const [commitStatus, setCommitStatus] = useState<'idle' | 'saving' | 'syncing'>('idle');
    const [syncError, setSyncError] = useState(false);
    const [systemMeta, setSystemMeta] = useState(db.getSystemMeta());

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const refreshAppState = () => {
        setProjects(db.getData('projects'));
        setClients(db.getData('clients'));
        setContacts(db.getData('contacts'));
        setCentres(db.getData('centres'));
        setFramingMaterials(db.getData('framingMaterials'));
        setFinishMaterials(db.getData('finishMaterials'));
        setSystemMeta(db.getSystemMeta());
    };

    const handleGoogleAuth = () => {
        const config = db.getSystemMeta();
        if (!config.googleClientId) {
            showNotification("Missing Google Client ID configuration.", "error");
            return;
        }

        setIsSyncing(true);
        try {
            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        setIsSyncing(false);
                        showNotification(`Google Error: ${response.error}`, "error");
                        return;
                    }
                    showNotification("Establishing identity handshake...", "warning");
                    const result = await db.syncWithCloud(response.access_token);
                    setIsSyncing(false);
                    if (result.success) {
                        showNotification(result.message, 'success');
                        refreshAppState();
                    } else {
                        showNotification(result.message, 'warning');
                    }
                }
            });
            client.requestAccessToken();
        } catch (e) {
            setIsSyncing(false);
            showNotification("Auth System Offline.", "error");
        }
    };

    const handleManualSync = async () => {
        if (!systemMeta.driveAccessToken) {
            handleGoogleAuth();
            return;
        }
        setIsSyncing(true);
        setSyncError(false);
        showNotification("Pulling latest cloud data...", "warning");
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(`SUCCESS: Vault synchronized with Google Drive.`, "success");
            refreshAppState();
        } else {
            setSyncError(true);
            showNotification(`SYNC FAILED: ${result.message}`, "error");
        }
    };

    const handleSaveProject = async () => {
        if (isViewer) return;
        if (!currentProject.projName || currentProject.projName.trim() === '') {
            showNotification('Project Name Required.', 'error');
            return;
        }

        setIsCommitting(true);
        setCommitStatus('saving');

        try {
            updateProject({ ...currentProject, updatedAt: new Date().toISOString() });
        } catch (e: any) {
            showNotification(`Local save failed: ${e.message}`, 'error');
            setIsCommitting(false);
            setCommitStatus('idle');
            return;
        }

        const meta = db.getSystemMeta();
        if (meta.driveAccessToken) {
            setCommitStatus('syncing');
            showNotification("Synchronizing with cloud repository...", "warning");

            const cloudResult = await db.pushToCloud();

            if (cloudResult.success) {
                showNotification(`SUCCESS: Project saved to Drive (${meta.connectedEmail})`, 'success');
                setSyncError(false);
            } else {
                showNotification(`CLOUD REPOSITORY ERROR: ${cloudResult.message}. Local copy preserved.`, 'error');
                setSyncError(true);
            }
            setSystemMeta(db.getSystemMeta());
        } else {
            showNotification(`LOCAL SAVE SUCCESSFUL: Link cloud for central repository synchronization.`, 'warning');
        }

        setIsCommitting(false);
        setCommitStatus('idle');
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
            showNotification(`Loaded Project: ${projectToLoad.projectCode}`);
        }
    };

    const handleLogout = () => {
        setCurrentUser(null);
    };

    const isCloudActive = !!systemMeta.driveAccessToken;
    const driveFileUrl = systemMeta.driveFileUrl || (systemMeta.driveFileId ? `https://drive.google.com/file/d/${systemMeta.driveFileId}/view` : null);

    let badgeClass = 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 shadow-inner';
    let dotClass = 'bg-slate-300';

    if (isSyncing || isCommitting) {
        badgeClass = 'bg-blue-50 border-blue-200 text-blue-600 animate-pulse shadow-md';
        dotClass = 'bg-blue-500 animate-ping';
    } else if (syncError) {
        badgeClass = 'bg-red-50 border-red-200 text-red-600 hover:bg-red-100 shadow-md';
        dotClass = 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    } else if (isCloudActive) {
        badgeClass = 'bg-white border-green-200 text-green-700 hover:border-green-400 shadow-sm';
        dotClass = 'bg-green-500 shadow-[0_0_5px_#10b981]';
    }

    return (
        <>
            <div className="flex flex-row md:flex-wrap gap-1.5 mb-2 bg-white p-1.5 rounded-xl shadow-sm justify-start md:justify-between items-center relative z-[40] border border-slate-200">
                <div className="flex flex-row flex-nowrap gap-1.5 items-center flex-grow overflow-x-auto no-scrollbar">
                    {onHome && (
                        <Button onClick={onHome} variant="outline" icon="fas fa-arrow-left" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black border-slate-300">
                            Dashboard
                        </Button>
                    )}
                    {!isViewer && (
                        <Button onClick={handleSaveProject} variant="primary" icon={isCommitting ? "fas fa-sync animate-spin" : "fas fa-save"} disabled={isCommitting} size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">
                            {commitStatus === 'saving' ? 'Saving...' : commitStatus === 'syncing' ? 'Syncing...' : 'Commit'}
                        </Button>
                    )}
                    <Button onClick={() => setIsProjectListOpen(true)} variant="success" icon="fas fa-folder-open" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Load</Button>
                    {!isViewer && <Button onClick={resetProject} variant="warning" icon="fas fa-file" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">New</Button>}
                    <div className="hidden md:block w-px bg-slate-200 mx-1 h-5 flex-shrink-0"></div>
                    <Button onClick={() => setView(View.TRACKER)} variant="primary" icon="fas fa-columns" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Tracker</Button>
                </div>

                <div className="flex items-center gap-2">
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1">
                            <button onClick={handleManualSync} disabled={isSyncing || isCommitting} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${badgeClass}`}>
                                <div className={`w-1.5 h-1.5 rounded-full ${dotClass}`}></div>
                                <span className="hidden sm:inline">
                                    {isSyncing ? 'Syncing...' : syncError ? 'Re-link' : isCloudActive ? (systemMeta.connectedEmail ? `Linked: ${systemMeta.connectedEmail}` : 'Sync Data') : 'Establish Link'}
                                </span>
                            </button>
                            {driveFileUrl && (
                                <a href={driveFileUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors" title="Locate Repository on Google Drive">
                                    <Icon name="fas fa-external-link-alt" className="text-[10px]" />
                                </a>
                            )}
                        </div>
                    </div>

                    {!isViewer && (
                        <div className="relative" ref={dbMenuRef}>
                            <button onClick={() => setIsDbMenuOpen(!isDbMenuOpen)} className={`flex items-center gap-2 px-3 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg border transition-all ${isDbMenuOpen ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-700 border-slate-300'}`}>
                                <Icon name="fas fa-database" />
                                <span className="hidden sm:inline">Vault</span>
                            </button>
                            {isDbMenuOpen && (
                                <div className="absolute top-[calc(100%+4px)] right-0 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 py-1 z-[100] animate-fade-in origin-top-right">
                                    <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1">Repositories</div>
                                    <button onClick={() => { setView(View.MANAGE_CLIENTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-building" className="text-indigo-600 w-4"/> Clients</button>
                                    <button onClick={() => { setView(View.MANAGE_CONTACTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-address-card" className="text-teal-600 w-4"/> Personnel</button>
                                    <button onClick={() => { setView(View.MANAGE_MATERIALS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-boxes" className="text-rose-600 w-4"/> Materials</button>
                                    <button onClick={() => { setView(View.FEEDBACK_JOURNAL); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-comments" className="text-amber-600 w-4"/> Feedback Journal</button>
                                    {isAdmin && (
                                        <>
                                            <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mt-1 mb-1">Control</div>
                                            <button onClick={() => { setView(View.MANAGE_USERS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold"><Icon name="fas fa-user-shield" className="text-blue-700 w-4"/> Access Keys</button>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    <button 
                        onClick={handleLogout} 
                        className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-slate-900 text-slate-400 hover:bg-red-600 hover:text-white transition-all shadow-sm group" 
                        title="Terminate Session"
                    >
                        <Icon name="fas fa-power-off" className="text-[10px]" />
                        <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Logout</span>
                    </button>
                </div>
            </div>
            <ProjectListModal isOpen={isProjectListOpen} onClose={() => setIsProjectListOpen(false)} onLoadProject={handleLoadProject} projects={projects} />
        </>
    );
};

export default Toolbar;

import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { View, Project, Client, Contact, Centre, FramingMaterial, FinishMaterial, CostingVariables, Job } from '../../types';
import Header from './Header';
import UserBar from './UserBar';
import StatusBar from '../project/StatusBar';
import Toolbar from '../project/Toolbar';
import TabContainer from '../tabs/TabContainer';
import ManageClientsPage from '../manage/ManageClientsPage';
import ManageContactsPage from '../manage/ManageContactsPage';
import ManageCentresPage from '../manage/ManageCentresPage';
import ManageMaterialsPage from '../manage/ManageMaterialsPage';
import ManageUsersPage from '../manage/ManageUsersPage';
import ProjectTrackerBoard from '../modules/ProjectTrackerBoard';
import FeedbackJournal from '../modules/FeedbackJournal';
import ForcePasswordChangeModal from '../auth/ForcePasswordChangeModal';
import { ProjectContextProvider } from '../../context/ProjectContext';
import { COST_VARS_STRUCTURE } from '../../constants';
import * as db from '../../services/db';
import { generateProjectCode } from '../../services/utils';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { useAppContext } from '../../hooks/useAppContext';

const createInitialProject = (defaultCostingVars: CostingVariables): Project => {
    return {
        projName: '', jobsThisYear: 1, year: new Date().getFullYear() % 100, projectCode: '',
        projectStatus: '0', prodCentre: '', prodCoords: '', clientName: '', clientMgr: '',
        clientPhone: '', clientEmail: '', clientAddr: '', destCitySelect: '', destCoords: '',
        projMgr: '', mgrPhone: '', mgrEmail: '', shippingLength: 0, shippingWidth: 0, shippingHeight: 0,
        jobs: [{ id: db.generateId(), name: 'Main Job', framingTakeOff: [], finishesTakeOff: [] }],
        costingVariables: { ...defaultCostingVars }
    };
};

const MainLayout: React.FC<{onBack?: () => void}> = ({ onBack }) => {
    const { currentUser, setCurrentUser, showNotification } = useAppContext();
    const [view, setView] = useState<View>(View.DASHBOARD);
    const [currentProject, setCurrentProject] = useState<Project>(() => createInitialProject({}));
    const [clients, setClients] = useState<Client[]>([]);
    const [contacts, setContacts] = useState<Contact[]>([]);
    const [centres, setCentres] = useState<Centre[]>([]);
    const [framingMaterials, setFramingMaterials] = useState<FramingMaterial[]>([]);
    const [finishMaterials, setFinishMaterials] = useState<FinishMaterial[]>([]);
    const [projects, setProjects] = useState<Project[]>([]);
    const [defaultCostingVariables, setDefaultCostingVariables] = useState<CostingVariables>({});
    const [isForcePasswordChangeOpen, setIsForcePasswordChangeOpen] = useState(false);

    const refreshLocalState = useCallback(() => {
        setClients(db.getData<Client>('clients'));
        setContacts(db.getData<Contact>('contacts'));
        setCentres(db.getData<Centre>('centres'));
        setFramingMaterials(db.getData<FramingMaterial>('framingMaterials'));
        setFinishMaterials(db.getData<FinishMaterial>('finishMaterials'));
        setProjects(db.getData<Project>('projects'));
    }, []);

    useEffect(() => {
        refreshLocalState();
        window.addEventListener('aeworks_db_update', refreshLocalState);
        return () => window.removeEventListener('aeworks_db_update', refreshLocalState);
    }, [refreshLocalState]);

    useEffect(() => {
        const loadedDefaults = db.getData<CostingVariables>('defaultCostingVariables')[0] || {};
        setDefaultCostingVariables(loadedDefaults);
        const autosaved = localStorage.getItem('autosave_current_project');
        if (autosaved) setCurrentProject(JSON.parse(autosaved));

        // Handle direct navigation to Feedback Journal from Landing Page
        const redirectView = localStorage.getItem('redirect_view');
        if (redirectView === 'FEEDBACK_JOURNAL') {
            setView(View.FEEDBACK_JOURNAL);
            localStorage.removeItem('redirect_view');
        } else if (redirectView === 'MANAGE_CENTRES') {
            setView(View.MANAGE_CENTRES);
            localStorage.removeItem('redirect_view');
        }
    }, []);

    useEffect(() => {
        if (currentProject.projName) {
            const code = generateProjectCode(currentProject.projName, currentProject.jobsThisYear, currentProject.year);
            if (code !== currentProject.projectCode) setCurrentProject(p => ({ ...p, projectCode: code }));
        }
    }, [currentProject.projName, currentProject.jobsThisYear, currentProject.year]);

    const updateProject = useCallback((project: Project) => {
        const existing = db.getData<Project>('projects');
        const idx = existing.findIndex(p => p.projectCode === project.projectCode);
        const updated = [...existing];
        if (idx > -1) updated[idx] = { ...project, updatedAt: new Date().toISOString() };
        else updated.push({ ...project, updatedAt: new Date().toISOString() });
        db.saveData('projects', updated);
        setProjects(updated);
        setCurrentProject(project);
    }, []);

    const projectContextValue = useMemo(() => ({
        currentProject, setCurrentProject, clients, setClients, contacts, setContacts,
        centres, setCentres, framingMaterials, setFramingMaterials, finishMaterials, setFinishMaterials,
        projects, setProjects, defaultCostingVariables, setDefaultCostingVariables,
        updateProject, updateGlobalDefaults: (v: any) => db.saveData('defaultCostingVariables', [v]),
        resetProject: () => setCurrentProject(createInitialProject(defaultCostingVariables))
    }), [currentProject, clients, contacts, centres, framingMaterials, finishMaterials, projects, defaultCostingVariables, updateProject]);

    const isFullWidth = view === View.TRACKER || view === View.FEEDBACK_JOURNAL;

    return (
        <ProjectContextProvider value={projectContextValue}>
            <div className={isFullWidth ? "w-full h-screen flex flex-col" : "max-w-7xl mx-auto p-2 h-screen flex flex-col"}>
                <div className="flex-shrink-0">
                    <UserBar />
                    <Header />
                    {view !== View.TRACKER && view !== View.FEEDBACK_JOURNAL && (
                        <StatusBar statusValue={parseInt(currentProject.projectStatus, 10)} onSetStatus={(v) => updateProject({...currentProject, projectStatus: v.toString()})} />
                    )}
                    <Toolbar setView={setView} onHome={onBack} />
                </div>
                <main className="flex-grow overflow-hidden relative">
                    {view === View.DASHBOARD && <TabContainer />}
                    {view === View.TRACKER && <ProjectTrackerBoard setView={setView} />}
                    {view === View.FEEDBACK_JOURNAL && <FeedbackJournal onBack={() => setView(View.DASHBOARD)} onOpenProject={(p) => { setCurrentProject(p); setView(View.DASHBOARD); }} />}
                    {view === View.MANAGE_CLIENTS && <ManageClientsPage goBack={() => setView(View.DASHBOARD)} />}
                    {view === View.MANAGE_CONTACTS && <ManageContactsPage goBack={() => setView(View.DASHBOARD)} />}
                    {view === View.MANAGE_MATERIALS && <ManageMaterialsPage goBack={() => setView(View.DASHBOARD)} />}
                    {view === View.MANAGE_USERS && <ManageUsersPage goBack={() => setView(View.DASHBOARD)} />}
                    {view === View.MANAGE_CENTRES && <ManageCentresPage goBack={() => setView(View.DASHBOARD)} />}
                </main>
                <ForcePasswordChangeModal isOpen={isForcePasswordChangeOpen} onClose={() => setIsForcePasswordChangeOpen(false)} />
            </div>
        </ProjectContextProvider>
    );
};

export default MainLayout;

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { User, Notification as NotificationType, AuthUser } from './types';
import { AppContextProvider } from './context/AppContext';
import MainLayout from './components/layout/MainLayout';
import LandingPage from './components/layout/LandingPage';
import LoginModal from './components/auth/LoginModal';
import Notification from './components/ui/Notification';
import LegacyAppContainer from './components/modules/LegacyAppContainer';
import WorkManager from './components/modules/WorkManager';
import PayrollManager from './components/modules/PayrollManager';
import PublicFeedbackPortal from './components/portal/PublicFeedbackPortal';
import { kpiMonitorHtml } from './components/modules/moduleContent';
import * as db from './services/db';
import { 
    INITIAL_USER_DATA, 
    INITIAL_CLIENTS_DATA, 
    INITIAL_CONTACTS_DATA, 
    INITIAL_CENTRES_DATA, 
    INITIAL_FRAMING_DATA, 
    INITIAL_FINISH_DATA,
    APP_VERSION
} from './constants';

type Module = 'dashboard' | 'project-board' | 'kpi-monitor' | 'payroll-manager' | 'work-manager' | 'feedback-portal' | 'feedback-journal';

const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [activeModule, setActiveModule] = useState<Module>('dashboard');
    const [notification, setNotification] = useState<NotificationType | null>(null);
    const [isInitialized, setIsInitialized] = useState(false);
    const [portalToken, setPortalToken] = useState<string | null>(null);

    const showNotification = useCallback((message: string, type: 'success' | 'error' | 'warning' = 'success') => {
        setNotification({ message, type });
        setTimeout(() => setNotification(null), 4000);
    }, []);

    useEffect(() => {
        const triggerSync = async () => {
            const meta = db.getSystemMeta();
            if (navigator.onLine && meta.driveAccessToken) {
                console.log("Auto Polling: Checking Cloud Vault & Inbox...");
                try {
                    await db.syncWithCloud(undefined, (code) => {
                        showNotification(`New Customer Feedback received for ${code}!`, 'warning');
                    });
                } catch (e) {}
            }
        };

        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                triggerSync();
            }
        };

        window.addEventListener('online', triggerSync);
        document.addEventListener('visibilitychange', handleVisibilityChange);

        const interval = setInterval(triggerSync, 120000);

        return () => {
            window.removeEventListener('online', triggerSync);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
            clearInterval(interval);
        };
    }, [showNotification]);

    useEffect(() => {
        const initDB = async () => {
            const meta = db.getSystemMeta();
            const existingUsers = db.getData<AuthUser>('users');

            const urlParams = new URLSearchParams(window.location.search);
            const token = urlParams.get('p_feedback');
            if (token) {
                setPortalToken(token);
                setActiveModule('feedback-portal');
            }

            if (existingUsers.length === 0 && !meta.driveAccessToken) {
                db.saveData('users', INITIAL_USER_DATA as any);
                db.saveData('clients', INITIAL_CLIENTS_DATA as any);
                db.saveData('contacts', INITIAL_CONTACTS_DATA as any);
                db.saveData('centres', INITIAL_CENTRES_DATA as any);
                db.saveData('framingMaterials', INITIAL_FRAMING_DATA as any);
                db.saveData('finishMaterials', INITIAL_FINISH_DATA as any);
            }

            if (navigator.onLine && meta.driveAccessToken) {
                try {
                    await db.syncWithCloud();
                } catch (e) {
                    console.warn("Initial sync deferred.");
                }
            }

            setIsInitialized(true);
        };
        initDB();
    }, []);

    const contextValue = useMemo(() => ({
        currentUser,
        setCurrentUser,
        showNotification
    }), [currentUser, showNotification]);

    const handleLogin = (user: User) => {
        setCurrentUser(user);
        setActiveModule('dashboard');
    };

    const handleNavigateFromLanding = (module: Module) => {
        if (module === 'feedback-journal') {
            localStorage.setItem('redirect_view', 'FEEDBACK_JOURNAL');
            setActiveModule('project-board');
        } else {
            setActiveModule(module);
        }
    };

    const renderContent = () => {
        if (activeModule === 'feedback-portal' && portalToken) {
            return <PublicFeedbackPortal token={portalToken} />;
        }

        switch (activeModule) {
            case 'project-board':
            case 'feedback-journal':
                return <MainLayout onBack={() => setActiveModule('dashboard')} />;
            case 'kpi-monitor':
                return <LegacyAppContainer htmlContent={kpiMonitorHtml} title="KPI Monitor" onBack={() => setActiveModule('dashboard')} />;
            case 'payroll-manager':
                return <PayrollManager onBack={() => setActiveModule('dashboard')} onNavigate={setActiveModule} />;
            case 'work-manager':
                return <WorkManager onBack={() => setActiveModule('dashboard')} />;
            case 'dashboard':
            default:
                return <LandingPage onNavigate={handleNavigateFromLanding} onLogout={() => setCurrentUser(null)} />;
        }
    };

    if (!isInitialized) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-slate-950 text-white">
                <div className="flex flex-col items-center gap-6">
                    <div className="relative">
                        <div className="absolute inset-0 bg-blue-500 blur-2xl opacity-20 animate-pulse"></div>
                        <i className="fas fa-circle-notch animate-spin text-5xl text-blue-500 relative z-10"></i>
                    </div>
                    <div className="text-center animate-pulse">
                        <p className="font-black tracking-[0.4em] text-[10px] uppercase mb-1">Connecting</p>
                        <p className="text-[8px] text-slate-600 font-bold uppercase">AEWorks Secure Vault</p>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <AppContextProvider value={contextValue}>
            {(currentUser || activeModule === 'feedback-portal') ? renderContent() : <LoginModal onLogin={handleLogin} />}
            {notification && <Notification message={notification.message} type={notification.type} />}
        </AppContextProvider>
    );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
    onHome?: () => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView, onHome }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, setCurrentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCommitting, setIsCommitting] = useState(false);
    const [commitStatus, setCommitStatus] = useState<'idle' | 'saving' | 'syncing'>('idle');
    const [syncError, setSyncError] = useState(false);
    const [systemMeta, setSystemMeta] = useState(db.getSystemMeta());

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const refreshAppState = () => {
        setProjects(db.getData('projects'));
        setClients(db.getData('clients'));
        setContacts(db.getData('contacts'));
        setCentres(db.getData('centres'));
        setFramingMaterials(db.getData('framingMaterials'));
        setFinishMaterials(db.getData('finishMaterials'));
        setSystemMeta(db.getSystemMeta());
    };

    const handleGoogleAuth = () => {
        const config = db.getSystemMeta();
        if (!config.googleClientId) {
            showNotification("Missing Google Client ID configuration.", "error");
            return;
        }

        setIsSyncing(true);
        try {
            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        setIsSyncing(false);
                        showNotification(`Google Error: ${response.error}`, "error");
                        return;
                    }
                    showNotification("Establishing identity handshake...", "warning");
                    const result = await db.syncWithCloud(response.access_token);
                    setIsSyncing(false);
                    if (result.success) {
                        showNotification(result.message, 'success');
                        refreshAppState();
                    } else {
                        showNotification(result.message, 'warning');
                    }
                }
            });
            client.requestAccessToken();
        } catch (e) {
            setIsSyncing(false);
            showNotification("Auth System Offline.", "error");
        }
    };

    const handleManualSync = async () => {
        if (!systemMeta.driveAccessToken) {
            handleGoogleAuth();
            return;
        }
        setIsSyncing(true);
        setSyncError(false);
        showNotification("Pulling latest cloud data...", "warning");
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(`SUCCESS: Vault synchronized with Google Drive.`, "success");
            refreshAppState();
        } else {
            setSyncError(true);
            showNotification(`SYNC FAILED: ${result.message}`, "error");
        }
    };

    const handleSaveProject = async () => {
        if (isViewer) return;
        if (!currentProject.projName || currentProject.projName.trim() === '') {
            showNotification('Project Name Required.', 'error');
            return;
        }

        setIsCommitting(true);
        setCommitStatus('saving');

        try {
            updateProject({ ...currentProject, updatedAt: new Date().toISOString() });
        } catch (e: any) {
            showNotification(`Local save failed: ${e.message}`, 'error');
            setIsCommitting(false);
            setCommitStatus('idle');
            return;
        }

        const meta = db.getSystemMeta();
        if (meta.driveAccessToken) {
            setCommitStatus('syncing');
            showNotification("Synchronizing with cloud repository...", "warning");

            const cloudResult = await db.pushToCloud();

            if (cloudResult.success) {
                showNotification(`SUCCESS: Project saved to Drive (${meta.connectedEmail})`, 'success');
                setSyncError(false);
            } else {
                showNotification(`CLOUD REPOSITORY ERROR: ${cloudResult.message}. Local copy preserved.`, 'error');
                setSyncError(true);
            }
            setSystemMeta(db.getSystemMeta());
        } else {
            showNotification(`LOCAL SAVE SUCCESSFUL: Link cloud for central repository synchronization.`, 'warning');
        }

        setIsCommitting(false);
        setCommitStatus('idle');
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
            showNotification(`Loaded Project: ${projectToLoad.projectCode}`);
        }
    };

    const handleLogout = () => {
        setCurrentUser(null);
    };

    const isCloudActive = !!systemMeta.driveAccessToken;
    const driveFileUrl = systemMeta.driveFileUrl || (systemMeta.driveFileId ? `https://drive.google.com/file/d/${systemMeta.driveFileId}/view` : null);

    let badgeClass = 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 shadow-inner';
    let dotClass = 'bg-slate-300';

    if (isSyncing || isCommitting) {
        badgeClass = 'bg-blue-50 border-blue-200 text-blue-600 animate-pulse shadow-md';
        dotClass = 'bg-blue-500 animate-ping';
    } else if (syncError) {
        badgeClass = 'bg-red-50 border-red-200 text-red-600 hover:bg-red-100 shadow-md';
        dotClass = 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    } else if (isCloudActive) {
        badgeClass = 'bg-white border-green-200 text-green-700 hover:border-green-400 shadow-sm';
        dotClass = 'bg-green-500 shadow-[0_0_5px_#10b981]';
    }

    return (
        <>
            <div className="flex flex-row md:flex-wrap gap-1.5 mb-2 bg-white p-1.5 rounded-xl shadow-sm justify-start md:justify-between items-center relative z-[40] border border-slate-200">
                <div className="flex flex-row flex-nowrap gap-1.5 items-center flex-grow overflow-x-auto no-scrollbar">
                    {!isViewer && (
                        <Button onClick={handleSaveProject} variant="primary" icon={isCommitting ? "fas fa-sync animate-spin" : "fas fa-save"} disabled={isCommitting} size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">
                            {commitStatus === 'saving' ? 'Saving...' : commitStatus === 'syncing' ? 'Syncing...' : 'Commit'}
                        </Button>
                    )}
                    <Button onClick={() => setIsProjectListOpen(true)} variant="success" icon="fas fa-folder-open" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Load</Button>
                    {!isViewer && <Button onClick={resetProject} variant="warning" icon="fas fa-file" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">New</Button>}
                    <div className="hidden md:block w-px bg-slate-200 mx-1 h-5 flex-shrink-0"></div>
                    <Button onClick={() => setView(View.TRACKER)} variant="primary" icon="fas fa-columns" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Tracker</Button>
                </div>

                <div className="flex items-center gap-2">
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1">
                            <button onClick={handleManualSync} disabled={isSyncing || isCommitting} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${badgeClass}`}>
                                <div className={`w-1.5 h-1.5 rounded-full ${dotClass}`}></div>
                                <span className="hidden sm:inline">
                                    {isSyncing ? 'Syncing...' : syncError ? 'Re-link' : isCloudActive ? (systemMeta.connectedEmail ? `Linked: ${systemMeta.connectedEmail}` : 'Sync Data') : 'Establish Link'}
                                </span>
                            </button>
                            {driveFileUrl && (
                                <a href={driveFileUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors" title="Locate Repository on Google Drive">
                                    <Icon name="fas fa-external-link-alt" className="text-[10px]" />
                                </a>
                            )}
                        </div>
                    </div>

                    {!isViewer && (
                        <div className="relative" ref={dbMenuRef}>
                            <button onClick={() => setIsDbMenuOpen(!isDbMenuOpen)} className={`flex items-center gap-2 px-3 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg border transition-all ${isDbMenuOpen ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-700 border-slate-300'}`}>
                                <Icon name="fas fa-database" />
                                <span className="hidden sm:inline">Vault</span>
                            </button>
                            {isDbMenuOpen && (
                                <div className="absolute top-[calc(100%+4px)] right-0 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 py-1 z-[100] animate-fade-in origin-top-right">
                                    <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1">Repositories</div>
                                    <button onClick={() => { setView(View.MANAGE_CLIENTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-building" className="text-indigo-600 w-4"/> Clients</button>
                                    <button onClick={() => { setView(View.MANAGE_CONTACTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-address-card" className="text-teal-600 w-4"/> Personnel</button>
                                    <button onClick={() => { setView(View.MANAGE_MATERIALS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-boxes" className="text-rose-600 w-4"/> Materials</button>
                                    <button onClick={() => { setView(View.FEEDBACK_JOURNAL); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-comments" className="text-amber-600 w-4"/> Feedback Journal</button>
                                    {isAdmin && (
                                        <>
                                            <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mt-1 mb-1">Control</div>
                                            <button onClick={() => { setView(View.MANAGE_USERS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold"><Icon name="fas fa-user-shield" className="text-blue-700 w-4"/> Access Keys</button>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    {onHome && (
                        <button 
                            onClick={onHome} 
                            className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white text-slate-700 border border-slate-300 hover:bg-slate-100 transition-all shadow-sm"
                        >
                            <Icon name="fas fa-arrow-left" className="text-[10px]" />
                            <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Dashboard</span>
                        </button>
                    )}

                    <button 
                        onClick={handleLogout} 
                        className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-slate-900 text-slate-400 hover:bg-red-600 hover:text-white transition-all shadow-sm group" 
                        title="Terminate Session"
                    >
                        <Icon name="fas fa-power-off" className="text-[10px]" />
                        <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Logout</span>
                    </button>
                </div>
            </div>
            <ProjectListModal isOpen={isProjectListOpen} onClose={() => setIsProjectListOpen(false)} onLoadProject={handleLoadProject} projects={projects} />
        </>
    );
};

export default Toolbar;

export const generateId = () => {
    try {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) {
            return crypto.randomUUID();
        }
    } catch (e) {}
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

export const getData = <T,>(key: string): T[] => {
    try {
        const data = localStorage.getItem(key);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        return [];
    }
};

export const saveData = <T,>(key: string, data: T[]): boolean => {
    try {
        const timestamp = new Date().toISOString();
        const dataWithMeta = data.map(item => {
            if (item && typeof item === 'object') {
                const typed = item as any;
                let stableId = typed.id;
                if (key === 'users') stableId = typed.email || typed.username || typed.id;
                if (key === 'projects') stableId = typed.projectCode || typed.id;
                if (key === 'clients') stableId = typed.name || typed.id;

                return {
                    ...item,
                    id: stableId || generateId(),
                    updatedAt: typed.updatedAt || timestamp
                };
            }
            return item;
        });
        localStorage.setItem(key, JSON.stringify(dataWithMeta));
        window.dispatchEvent(new CustomEvent('aeworks_db_update', { detail: { key } }));
        return true;
    } catch (error) {
        return false;
    }
};

export const getSystemLogo = (): string | null => localStorage.getItem('system_logo');
export const saveSystemLogo = (base64Data: string | null): void => {
    if (base64Data) localStorage.setItem('system_logo', base64Data);
    else localStorage.removeItem('system_logo');
};

export interface SystemMeta {
    id: string;
    versionLabel: string;
    lastCloudSync?: string;
    syncApiKey: string; 
    autoSync: boolean;
    backupLocation?: string;
    driveFileId?: string;
    driveAccessToken?: string;
    googleClientId?: string; 
    connectedEmail?: string;
    driveFileUrl?: string;
    activeCollaborators?: string[];
}

const GLOBAL_ENV_CLIENT_ID = (import.meta as any).env?.VITE_GOOGLE_CLIENT_ID;
const HARDCODED_FALLBACK_ID = '674092109435-96p21r75k1jgr7t1f0l4eohf5c49k23t.apps.googleusercontent.com';
const MASTER_CLIENT_ID = GLOBAL_ENV_CLIENT_ID || HARDCODED_FALLBACK_ID;

export const getSystemMeta = (): SystemMeta => {
    const raw = localStorage.getItem('system_meta');
    const defaultMeta: SystemMeta = { 
        id: 'meta', 
        versionLabel: 'v4.6 Multi-Dev Sync', 
        syncApiKey: '',
        autoSync: true,
        backupLocation: 'Google_Drive_AEWorks',
        googleClientId: MASTER_CLIENT_ID
    };
    if (!raw) return defaultMeta;
    try {
        const data = JSON.parse(raw);
        const meta = Array.isArray(data) ? data[0] : data;
        return { ...defaultMeta, ...meta };
    } catch {
        return defaultMeta;
    }
};

export const updateSystemMeta = (meta: Partial<SystemMeta>): void => {
    const current = getSystemMeta();
    localStorage.setItem('system_meta', JSON.stringify([{ ...current, ...meta }]));
};

export const DB_KEYS = ['clients', 'contacts', 'centres', 'framingMaterials', 'finishMaterials', 'projects', 'users', 'payrollRuns', 'defaultCostingVariables', 'productionLogs', 'locationExpenses', 'unassignedFeedback'];
const MASTER_FILE_NAME = "AEWORKS_MASTER_VAULT.json";
const INBOX_FOLDER_NAME = "AEWORKS_INBOX";

const getDriveHeaders = (token: string) => ({
    'Authorization': `Bearer ${token}`
});

export const syncInboxFeedback = async (onNewFeedback?: (code: string) => void): Promise<{ success: boolean, count: number }> => {
    const meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, count: 0 };

    try {
        console.log("Inbox Sync: Searching for folder", INBOX_FOLDER_NAME);
        const folderQuery = encodeURIComponent(`name='${INBOX_FOLDER_NAME}' and mimeType='application/vnd.google-apps.folder' and trashed=false`);
        const folderRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${folderQuery}&supportsAllDrives=true&includeItemsFromAllDrives=true`, { headers: getDriveHeaders(token) });
        const folderData = await folderRes.json();

        if (!folderData.files || folderData.files.length === 0) {
            console.warn("Inbox Sync: AEWORKS_INBOX folder not found or inaccessible.");
            return { success: true, count: 0 };
        }

        let totalProcessed = 0;
        const projects = getData<any>('projects');
        const unassigned = getData<any>('unassignedFeedback');
        let projectsUpdated = false;
        let unassignedUpdated = false;
        const normalize = (s: string) => s.replace(/[^A-Z0-9]/gi, '').toUpperCase();

        for (const folder of folderData.files) {
            const filesQuery = encodeURIComponent(`'${folder.id}' in parents and trashed=false`);
            const filesRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${filesQuery}&fields=files(id, name, mimeType)&supportsAllDrives=true&includeItemsFromAllDrives=true`, { headers: getDriveHeaders(token) });
            const filesData = await filesRes.json();

            const files = filesData.files || [];
            if (files.length === 0) continue;

            for (const file of files) {
                try {
                    const contentRes = await fetch(`https://www.googleapis.com/drive/v3/files/${file.id}?alt=media`, { headers: getDriveHeaders(token) });
                    if (!contentRes.ok) continue;

                    const rawText = await contentRes.text();
                    let feedbackData;
                    try {
                        feedbackData = JSON.parse(rawText.trim());
                    } catch (parseErr) {
                        continue;
                    }

                    if (!feedbackData || !feedbackData.code) continue;

                    const incomingNormal = normalize(feedbackData.code);
                    const incomingBase = normalize(feedbackData.code.split('.')[0]);

                    const projIdx = projects.findIndex((p: any) => {
                        const localNormal = normalize(p.projectCode || '');
                        const localBase = normalize((p.projectCode || '').split('.')[0]);
                        return localNormal === incomingNormal || localBase === incomingBase;
                    });

                    if (projIdx > -1) {
                        const project = projects[projIdx];
                        project.trackingData = {
                            ...(project.trackingData || {}),
                            customerFeedback: feedbackData.feedback,
                            feedbackStatus: 'received'
                        };

                        // AUTO-ACTIVATE CLOSEOUT: Advance status to 100 if project was shipped (95)
                        if (project.projectStatus === '95') {
                            project.projectStatus = '100';
                            console.log(`Inbox Sync: Auto-advanced project ${project.projectCode} to Closeout stage.`);
                        }

                        project.updatedAt = new Date().toISOString();
                        projectsUpdated = true;
                        if (onNewFeedback) onNewFeedback(project.projectCode);
                    } else {
                        unassigned.push({
                            id: generateId(),
                            originalCode: feedbackData.code,
                            feedback: feedbackData.feedback,
                            receivedAt: new Date().toISOString()
                        });
                        unassignedUpdated = true;
                    }

                    const delRes = await fetch(`https://www.googleapis.com/drive/v3/files/${file.id}?supportsAllDrives=true`, { method: 'DELETE', headers: getDriveHeaders(token) });
                    if (delRes.ok) totalProcessed++;
                } catch (e) {
                    console.error(`Inbox Sync failure for file ${file.id}:`, e);
                }
            }
        }

        if (projectsUpdated) saveData('projects', projects);
        if (unassignedUpdated) saveData('unassignedFeedback', unassigned);

        if (projectsUpdated || unassignedUpdated) {
            window.dispatchEvent(new CustomEvent('aeworks_db_update', { detail: { key: 'projects' } }));
            await pushToCloud();
        }

        return { success: true, count: totalProcessed };
    } catch (err) {
        return { success: false, count: 0 };
    }
};

export const syncWithCloud = async (providedToken?: string, onNewFeedback?: (code: string) => void): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = providedToken || meta.driveAccessToken;
    if (!token) return { success: false, message: "Drive Auth Required." };

    try {
        const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
        const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id, name)&supportsAllDrives=true&includeItemsFromAllDrives=true`, { headers: getDriveHeaders(token) });
        const searchData = await searchRes.json();
        const foundFile = (searchData.files || [])[0];

        if (!foundFile) {
            await pushToCloud();
            return { success: true, message: "Vault Established." };
        }

        const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${foundFile.id}?alt=media`, { headers: getDriveHeaders(token) });
        const actualData = await fileRes.json();

        DB_KEYS.forEach(key => {
            const local = getData<any>(key);
            const remote = actualData[key] || [];
            const merged = mergeDatasets(key, local, remote);
            localStorage.setItem(key, JSON.stringify(merged));
        });

        updateSystemMeta({ driveFileId: foundFile.id, driveAccessToken: token, lastCloudSync: new Date().toISOString() });

        await syncInboxFeedback(onNewFeedback);

        window.dispatchEvent(new CustomEvent('aeworks_db_update', { detail: { key: 'all' } }));
        return { success: true, message: "Synchronized." };
    } catch (err: any) {
        return { success: false, message: "Connection Error." };
    }
};

export const pushToCloud = async (): Promise<{success: boolean, message: string}> => {
    let meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, message: "Offline." };

    try {
        const fullDB: any = { _meta: { lastPush: new Date().toISOString() } };
        DB_KEYS.forEach(key => fullDB[key] = getData(key));
        const metadata = { name: MASTER_FILE_NAME, mimeType: 'application/json' };
        let fileId = meta.driveFileId;

        if (!fileId) {
            const createRes = await fetch('https://www.googleapis.com/drive/v3/files?supportsAllDrives=true', {
                method: 'POST', 
                headers: { ...getDriveHeaders(token), 'Content-Type': 'application/json' }, 
                body: JSON.stringify(metadata)
            });
            const createData = await createRes.json();
            fileId = createData.id;
            updateSystemMeta({ driveFileId: fileId });
        }

        await fetch(`https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media&supportsAllDrives=true`, {
            method: 'PATCH', 
            headers: { ...getDriveHeaders(token), 'Content-Type': 'application/json' }, 
            body: JSON.stringify(fullDB)
        });

        updateSystemMeta({ lastCloudSync: new Date().toISOString() });
        return { success: true, message: "Push Success." };
    } catch (err: any) {
        return { success: false, message: "Push Error." };
    }
};

const mergeDatasets = (dbKey: string, local: any[], remote: any[]) => {
    const map = new Map();
    const getStableId = (item: any) => {
        if (dbKey === 'users') return item.email || item.username || item.id;
        if (dbKey === 'projects') return item.projectCode || item.id;
        if (dbKey === 'clients') return item.name || item.id;
        return item.id;
    };
    remote.forEach(i => map.set(getStableId(i), i));
    local.forEach(i => {
        const id = getStableId(i);
        const rem = map.get(id);
        if (!rem || new Date(i.updatedAt || 0) > new Date(rem.updatedAt || 0)) map.set(id, i);
    });
    return Array.from(map.values());
};

